1	/**
2	 * expand_trace.js — regenerate the FULL per-step trace from a LIGHT game log.
3	 *
4	 * A light log { seed, config, action_log } plus the deterministic env reproduces the
5	 * entire game exactly. This replays it and emits the full per-step trace (obs, reward,
6	 * event, done), and verifies the replay against the light log's checkpoints.
7	 *
8	 * Usage:
9	 *   node expand_trace.js game_logs/game_s1_xxx.json            # prints summary + verify
10	 *   node expand_trace.js game_logs/game_s1_xxx.json out.jsonl  # also write per-step JSONL
11	 */
12	"use strict";
13	
14	const fs = require("fs");
15	const crypto = require("crypto");
16	const { RogueEnv } = require("./env.bundle.js");
17	
18	function hashObs(obs) {
19	  return crypto.createHash("sha1").update(JSON.stringify(obs)).digest("hex").slice(0, 12);
20	}
21	
22	function main() {
23	  const inPath = process.argv[2];
24	  const outPath = process.argv[3];
25	  if (!inPath) {
26	    console.log("usage: node expand_trace.js <light_log.json> [out.jsonl]");
27	    process.exit(1);
28	  }
29	  const log = JSON.parse(fs.readFileSync(inPath, "utf8"));
30	  const cfg = log.config || {};
31	  const field = cfg.field || { w: 360, h: 640 };
32	  // Reconstruct the env at the same field size the log recorded.
33	  const env = new RogueEnv({ windowWidth: field.w, windowHeight: field.h });
34	  if (env.W !== field.w || env.H !== field.h) {
35	    console.error(`WARN: env field ${env.W}x${env.H} != log field ${field.w}x${field.h} (run in a fresh process for an exact match).`);
36	  }
37	  const config = {
38	    speed_cap: cfg.speed_cap === "inf" ? Infinity : Number(cfg.speed_cap),
39	    frame_skip: cfg.frame_skip || 1,
40	    max_steps: cfg.max_steps || 200000,
41	    character_id: cfg.character_id || "striker",
42	  };
43	
44	  let { obs } = env.reset(log.seed, config);
45	  const lines = outPath ? [] : null; // accumulate then write synchronously (no flush race)
46	  const checkpoints = {};
47	  for (const c of log.checkpoints || []) checkpoints[c.step] = c.obs_hash;
48	  let step = 0;
49	  let mismatches = 0;
50	  let last = { obs, reward_info: obs.reward_info, event: null, done: false };
51	  for (const action of log.action_log) {
52	    last = env.step(action);
53	    step += 1;
54	    if (lines) lines.push(JSON.stringify({ step, action, obs: last.obs, reward_info: last.reward_info, event: last.event, done: last.done }));
55	    if (checkpoints[step] && hashObs(last.obs) !== checkpoints[step]) mismatches += 1;
56	    if (last.done) break;
57	  }
58	  if (lines) fs.writeFileSync(outPath, lines.join("\n") + "\n");
59	
60	  const ri = last.reward_info;
61	  const verified = mismatches === 0 ? "✓ checkpoints match" : `✗ ${mismatches} checkpoint mismatch(es)`;
62	  console.log(`expanded ${step} steps from ${inPath}  [${verified}]`);
63	  console.log(`  game_version ${log.game_version} | seed ${log.seed} | progress ${ri.progress} | cleared ${ri.boss_cleared} | reason ${ri.done_reason}`);
64	  if (outPath) console.log(`  full per-step trace -> ${outPath}`);
65	  process.exit(mismatches === 0 ? 0 : 2);
66	}
67	
68	main();
69

