"use strict";
const { RogueEnv } = require("./env.bundle.js");

const env = new RogueEnv();
let { obs, reward_info } = env.reset(1, { speed_cap: 40, frame_skip: 1, max_steps: 90000 });

console.log("=== INITIAL STATE ===");
console.log("field:", JSON.stringify(obs.field));
console.log("player:", JSON.stringify(obs.player, null, 1));
console.log("wave:", obs.wave, "frame:", obs.frame, "time_ms:", obs.time_ms);
console.log("reward_info:", JSON.stringify(reward_info, null, 1));
console.log("objects count:", obs.objects.length);
console.log("initial objects sample:", JSON.stringify(obs.objects.slice(0, 8), null, 1));

// Simple policy: stay near bottom center, dodge nearest bullet a bit
function simplePolicy(obs) {
  const [px, py] = obs.player.pos;
  const W = obs.field.w, H = obs.field.h;
  // target: bottom center-ish
  let tx = W / 2, ty = H * 0.8;
  // dodge nearest bullet
  let nearest = null, nd = 1e9;
  for (const o of obs.objects) {
    if (o.type === "enemy_bullet") {
      const dx = o.pos[0] - px, dy = o.pos[1] - py;
      const d = Math.hypot(dx, dy);
      if (d < nd) { nd = d; nearest = o; }
    }
  }
  let mvx = (tx - px) * 0.2, mvy = (ty - py) * 0.2;
  if (nearest && nd < 60) {
    mvx -= (nearest.pos[0] - px) * 0.5;
    mvy -= (nearest.pos[1] - py) * 0.5;
  }
  const mag = Math.hypot(mvx, mvy);
  if (mag > 40) { mvx = mvx / mag * 40; mvy = mvy / mag * 40; }
  return [mvx, mvy];
}

// Track unique enemy types, item types, upgrades, boss info
const enemyTypes = {};
const itemTypes = {};
const upgradesSeen = {};
const events = {};
let bossInfo = null;
let maxWave = 1;
let lastLevel = 1;
const levelFrames = [];

let done = false;
let steps = 0;
let pendingUpgrade = null;
const samplePoints = [60, 300, 600, 1200, 2000, 3000, 5000, 8000, 12000, 20000, 30000, 50000, 70000, 89000];
let sampleIdx = 0;

while (!done && steps < 90000) {
  let action;
  if (obs.pending_upgrade && obs.pending_upgrade.options.length) {
    // record options
    for (const opt of obs.pending_upgrade.options) {
      upgradesSeen[opt.id] = opt;
    }
    action = { move: [0, 0], upgrade_choice: 0 };
  } else {
    action = { move: simplePolicy(obs), upgrade_choice: null };
  }
  const r = env.step(action);
  obs = r.obs;
  reward_info = r.reward_info;
  done = r.done;
  steps++;

  if (r.event) {
    events[r.event.kind] = (events[r.event.kind] || 0) + 1;
    if (r.event.kind === "boss_phase") {
      bossInfo = r.event;
    }
    if (r.event.kind === "level_up") {
      // nothing
    }
  }

  for (const o of obs.objects) {
    if (o.type === "enemy" || o.type === "enemy_elite") {
      enemyTypes[o.enemy_type] = (enemyTypes[o.enemy_type] || 0) + 1;
    }
    if (o.type === "item") {
      itemTypes[o.item_type] = (itemTypes[o.item_type] || 0) + 1;
    }
  }
  if (obs.wave > maxWave) {
    maxWave = obs.wave;
    console.log(`>> WAVE ${obs.wave} at step ${steps}, frame ${obs.frame}, time ${Math.round(obs.time_ms)}ms, player hp ${obs.player.hp}/${obs.player.max_hp}, level ${obs.player.level}`);
  }
  if (obs.player.level > lastLevel) {
    levelFrames.push({ level: obs.player.level, step: steps, frame: obs.frame });
    lastLevel = obs.player.level;
  }

  // sample detailed state
  if (sampleIdx < samplePoints.length && steps >= samplePoints[sampleIdx]) {
    const bosses = obs.objects.filter(o => o.type === "boss");
    console.log(`--- step ${steps} f${obs.frame} t${Math.round(obs.time_ms)}ms wave${obs.wave} lvl${obs.player.level} hp${obs.player.hp}/${obs.player.max_hp} sh${obs.player.shield_hp} | objs:${obs.objects.length} | shoot_int:${obs.player.shoot_interval_ms} side:${obs.player.side_bullets} pierce:${obs.player.pierce} sat:${obs.player.satellites} magnet:${obs.player.magnet_range} | progress:${reward_info.progress} score:${reward_info.score} kills:${reward_info.kills} boss_active:${reward_info.boss_active}`);
    if (bosses.length) console.log("    BOSS:", JSON.stringify(bosses[0]));
    sampleIdx++;
  }
}

console.log("\n=== FINAL ===");
console.log("steps:", steps, "done:", done);
console.log("reward_info:", JSON.stringify(reward_info, null, 1));
console.log("events:", JSON.stringify(events));
console.log("enemy types seen:", Object.keys(enemyTypes));
console.log("item types seen:", Object.keys(itemTypes));
console.log("level progression (first 25):", JSON.stringify(levelFrames.slice(0, 25)));
console.log("max level reached:", lastLevel);
console.log("\n=== UPGRADES SEEN ===");
for (const id in upgradesSeen) {
  const u = upgradesSeen[id];
  console.log(`  [${u.rarity}] ${u.id} "${u.name}": ${u.desc}`);
}
if (bossInfo) console.log("\nLast boss event:", JSON.stringify(bossInfo));

