const { RogueEnv } = require("./env.bundle.js");

const env = new RogueEnv();
let { obs, reward_info } = env.reset(1, { speed_cap: 40, frame_skip: 1, max_steps: 90000 });

// Track player bullets to learn fire direction & damage
function describeBullets(obs) {
  const pb = obs.objects.filter(o => o.type === "player_bullet");
  const eb = obs.objects.filter(o => o.type === "enemy_bullet");
  return { pb, eb };
}

// Aggressive policy: move toward nearest enemy horizontally, stay low; collect exp items
function policy(obs) {
  const [px, py] = obs.player.pos;
  const W = obs.field.w, H = obs.field.h;
  // gather
  let enemies = obs.objects.filter(o => o.type === "enemy" || o.type === "enemy_elite" || o.type === "boss");
  let items = obs.objects.filter(o => o.type === "item");
  let bullets = obs.objects.filter(o => o.type === "enemy_bullet");

  // Aim: line up horizontally under nearest enemy (to hit with upward autofire)
  let tx = W / 2, ty = H * 0.78;
  if (enemies.length) {
    // nearest enemy by y (closest above)
    let target = enemies[0];
    let best = 1e9;
    for (const e of enemies) {
      const d = Math.abs(e.pos[0] - px) + Math.abs(e.pos[1] - py) * 0.3;
      if (d < best) { best = d; target = e; }
    }
    tx = target.pos[0];
  }
  // collect nearby items
  let itTarget = null, itd = 1e9;
  for (const it of items) {
    const d = Math.hypot(it.pos[0] - px, it.pos[1] - py);
    if (d < itd) { itd = d; itTarget = it; }
  }
  let mvx = (tx - px) * 0.3;
  let mvy = (ty - py) * 0.3;
  if (itTarget && itd < 120) {
    mvx = (itTarget.pos[0] - px) * 0.3;
    mvy = (itTarget.pos[1] - py) * 0.3;
  }
  // dodge bullets
  for (const b of bullets) {
    const dx = px - b.pos[0], dy = py - b.pos[1];
    const d = Math.hypot(dx, dy);
    if (d < 50 && d > 0.001) {
      mvx += dx / d * (50 - d) * 0.8;
      mvy += dy / d * (50 - d) * 0.8;
    }
  }
  const mag = Math.hypot(mvx, mvy);
  if (mag > 40) { mvx = mvx / mag * 40; mvy = mvy / mag * 40; }
  return [mvx, mvy];
}

let done = false, steps = 0;
let lastHp = obs.player.hp;
let upgradeCount = 0;
const hpDrops = [];

while (!done && steps < 90000) {
  let action;
  if (obs.pending_upgrade && obs.pending_upgrade.options.length) {
    action = { move: [0, 0], upgrade_choice: 0 };
    upgradeCount++;
  } else {
    action = { move: policy(obs), upgrade_choice: null };
  }
  const r = env.step(action);
  obs = r.obs; reward_info = r.reward_info; done = r.done; steps++;

  if (obs.player.hp < lastHp) {
    hpDrops.push({ step: steps, hp: obs.player.hp, lost: lastHp - obs.player.hp });
  }
  lastHp = obs.player.hp;

  if (steps === 120) {
    const { pb, eb } = describeBullets(obs);
    console.log("=== at step 120 ===");
    console.log("player pos:", obs.player.pos);
    console.log("player_bullets:", JSON.stringify(pb.slice(0, 5)));
    console.log("enemy_bullets:", JSON.stringify(eb.slice(0, 5)));
    console.log("enemies:", JSON.stringify(obs.objects.filter(o=>o.type.startsWith("enemy")).slice(0,5)));
  }
}

console.log("\n=== FINAL (aggressive policy) ===");
console.log("steps:", steps, "level:", reward_info.level, "kills:", reward_info.kills, "wave:", reward_info.wave);
console.log("progress:", reward_info.progress, "score:", reward_info.score, "boss_reached:", reward_info.boss_reached);
console.log("done_reason:", reward_info.done_reason, "survived_ms:", Math.round(reward_info.survived_ms));
console.log("upgradeCount (panels):", upgradeCount);
console.log("hp drops count:", hpDrops.length, "first 10:", JSON.stringify(hpDrops.slice(0, 10)));
console.log("total hp lost:", hpDrops.reduce((a,b)=>a+b.lost,0));

