"use strict";
const { RogueEnv } = require("./env.bundle.js");

const env = new RogueEnv();
let { obs } = env.reset(1, { speed_cap: 40, frame_skip: 1, max_steps: 90000 });

// Policy that aligns under nearest enemy, dodges bullets, but track damage sources
function policy(obs) {
  const [px, py] = obs.player.pos;
  const W = obs.field.w, H = obs.field.h;
  let enemies = obs.objects.filter(o => o.type === "enemy" || o.type === "enemy_elite" || o.type === "boss");
  let bullets = obs.objects.filter(o => o.type === "enemy_bullet");
  let tx = W / 2, ty = H * 0.82;
  if (enemies.length) {
    let target = enemies[0], best = 1e9;
    for (const e of enemies) {
      const d = Math.abs(e.pos[0] - px) + Math.max(0, e.pos[1]-py)*0.1;
      if (d < best) { best = d; target = e; }
    }
    tx = target.pos[0];
  }
  let mvx = (tx - px) * 0.3, mvy = (ty - py) * 0.3;
  for (const b of bullets) {
    const dx = px - b.pos[0], dy = py - b.pos[1];
    const d = Math.hypot(dx, dy);
    if (d < 55 && d > 0.001) { mvx += dx / d * (55 - d) * 0.9; mvy += dy / d * (55 - d) * 0.9; }
  }
  // avoid body contact with enemies
  for (const e of enemies) {
    const dx = px - e.pos[0], dy = py - e.pos[1];
    const d = Math.hypot(dx, dy);
    const rad = (e.size[0]+24)/2 + 8;
    if (d < rad && d > 0.001) { mvx += dx/d*(rad-d)*1.0; mvy += dy/d*(rad-d)*1.0; }
  }
  const mag = Math.hypot(mvx, mvy);
  if (mag > 40) { mvx = mvx / mag * 40; mvy = mvy / mag * 40; }
  return [mvx, mvy];
}

let done = false, steps = 0;
let lastHp = obs.player.hp;
const enemyStats = {};

while (!done && steps < 90000) {
  let action;
  if (obs.pending_upgrade && obs.pending_upgrade.options.length) {
    action = { move: [0, 0], upgrade_choice: 0 };
  } else {
    action = { move: policy(obs), upgrade_choice: null };
  }
  // record enemy stats before stepping
  for (const o of obs.objects) {
    if (o.type === "enemy" || o.type === "enemy_elite") {
      const key = o.type + ":" + o.enemy_type;
      if (!enemyStats[key]) enemyStats[key] = { max_hp: o.max_hp, size: o.size[0].toFixed(1), velseen: new Set() };
      enemyStats[key].velseen.add(o.vel[0].toFixed(1)+","+o.vel[1].toFixed(1));
    }
  }
  const r = env.step(action);

  if (r.obs.player.hp < lastHp) {
    const lost = lastHp - r.obs.player.hp;
    const [px, py] = obs.player.pos; // pos before step
    // find nearest enemy & bullet in PREVIOUS obs
    let ne=null,nd=1e9,nb=null,nbd=1e9;
    for (const o of obs.objects) {
