// Policy that aligns under nearest enemy, dodges bullets, but track damage sources
function policy(obs) {
  const [px, py] = obs.player.pos;
  const W = obs.field.w, H = obs.field.h;
  let enemies = obs.objects.filter(o => o.type === "enemy" || o.type === "enemy_elite" || o.type === "boss");
  let bullets = obs.objects.filter(o => o.type === "enemy_bullet");
  let tx = W / 2, ty = H * 0.82;
  if (enemies.length) {
    let target = enemies[0], best = 1e9;
    for (const e of enemies) {
      const d = Math.abs(e.pos[0] - px) + Math.max(0, e.pos[1]-py)*0.1;
      if (d < best) { best = d; target = e; }
    }
    tx = target.pos[0];
  }
  let mvx = (tx - px) * 0.3, mvy = (ty - py) * 0.3;
  for (const b of bullets) {
    const dx = px - b.pos[0], dy = py - b.pos[1];
    const d = Math.hypot(dx, dy);
    if (d < 55 && d > 0.001) { mvx += dx / d * (55 - d) * 0.9; mvy += dy / d * (55 - d) * 0.9; }
  }
