"use strict";
const { RogueEnv } = require("./env.bundle.js");

// Candidate-move survival policy with offense + pickup incentives.
function policy(obs, mem) {
  const [px, py] = obs.player.pos;
  const W = obs.field.w, H = obs.field.h;
  const pr = Math.max(obs.player.size[0], obs.player.size[1]) / 2;

  const enemies = [], bullets = [], items = [];
  for (const o of obs.objects) {
    if (o.type === "enemy" || o.type === "enemy_elite") enemies.push(o);
    else if (o.type === "boss") enemies.push(o);
    else if (o.type === "enemy_bullet") bullets.push(o);
    else if (o.type === "item") items.push(o);
  }

  const SPEED = 40;
  // candidate moves: 0 + 16 directions at full + half speed
  const cands = [[0, 0]];
  for (let a = 0; a < 16; a++) {
    const ang = (a / 16) * Math.PI * 2;
    cands.push([Math.cos(ang) * SPEED, Math.sin(ang) * SPEED]);
    cands.push([Math.cos(ang) * SPEED * 0.5, Math.sin(ang) * SPEED * 0.5]);
  }

  // pick a kill target: nearest enemy roughly above
  let killTarget = null, kbest = 1e9;
  for (const e of enemies) {
    if (e.in_cutscene) continue;
    const d = Math.abs(e.pos[0] - px) * 1.0 + Math.max(0, e.pos[1] - py + 20) * 0.2;
    if (d < kbest) { kbest = d; killTarget = e; }
  }
  // pickup target: nearest item
  let itTarget = null, ibest = 1e9;
  for (const it of items) {
    const d = Math.hypot(it.pos[0] - px, it.pos[1] - py);
    if (d < ibest) { ibest = d; itTarget = it; }
  }

  const HORIZON = 18;
  function scoreMove(mv) {
    const nx = Math.max(pr, Math.min(W - pr, px + mv[0]));
    const ny = Math.max(pr, Math.min(H - pr, py + mv[1]));
    let danger = 0;
    // bullet threat over horizon
    for (const b of bullets) {
      for (let t = 1; t <= HORIZON; t += 3) {
        const bx = b.pos[0] + b.vel[0] * t, by = b.pos[1] + b.vel[1] * t;
        const d = Math.hypot(bx - nx, by - ny);
        const hitR = pr + b.size[0] / 2 + 2;
        if (d < hitR + 6) danger += (hitR + 6 - d) * (b.dmg || 300) * 0.02 / (1 + t * 0.3);
      }
    }
    // enemy body threat (contact = death). Heavy penalty for proximity.
    for (const e of enemies) {
      for (let t = 0; t <= HORIZON; t += 3) {
        const ex = e.pos[0] + e.vel[0] * t, ey = e.pos[1] + e.vel[1] * t;
        const d = Math.hypot(ex - nx, ey - ny);
        const hitR = pr + e.size[0] / 2;
        if (d < hitR + 14) danger += (hitR + 14 - d) * 200 / (1 + t * 0.2);
      }
    }
    // edge penalty
    const edge = Math.min(nx - pr, W - pr - nx, ny - pr, H - pr - ny);
    if (edge < 30) danger += (30 - edge) * 3;
    // prefer lower third (room to maneuver, enemies come from top)
    danger += Math.max(0, (H * 0.55) - ny) * 0.5;

    let reward = 0;
    if (killTarget) reward += Math.max(0, 40 - Math.abs(killTarget.pos[0] - nx)) * 2;
    if (itTarget && ibest < 150) reward += Math.max(0, 100 - Math.hypot(itTarget.pos[0] - nx, itTarget.pos[1] - ny)) * 1.0;
    return reward - danger;
  }

  let bestMv = [0, 0], bestScore = -1e18;
  for (const mv of cands) {
    const s = scoreMove(mv);
    if (s > bestScore) { bestScore = s; bestMv = mv; }
  }
  return bestMv;
}

function run(seed, maxSteps, logUpgrades) {
  const env = new RogueEnv();
  let { obs } = env.reset(seed, { speed_cap: 40, frame_skip: 1, max_steps: maxSteps });
  let done = false, steps = 0;
  const upgrades = {};
  let bossSeen = false, bossMaxHp = 0, bossMinFrac = 1, bossVariant = null;
  let bossPhases = [];
  let mem = {};
  while (!done && steps < maxSteps) {
    let action;
    if (obs.pending_upgrade && obs.pending_upgrade.options.length) {
      for (const opt of obs.pending_upgrade.options) upgrades[opt.id] = opt;
      // choose by simple heuristic favoring offense
      action = { move: [0, 0], upgrade_choice: chooseUpg(obs.pending_upgrade.options) };
    } else {
      action = { move: policy(obs, mem), upgrade_choice: null };
    }
    const r = env.step(action);
    obs = r.obs; done = r.done; steps++;
    if (r.event && r.event.kind === "boss_phase") {
      if (!bossSeen) { bossSeen = true; bossMaxHp = r.event.max_hp; bossVariant = r.event.variant; }
      bossPhases.push({ step: steps, variant: r.event.variant, hp: r.event.hp, max_hp: r.event.max_hp, layers: r.event.hp_layers_left, cut: r.event.in_cutscene, first: r.event.first_sight });
    }
    if (obs.reward_info.boss_hp_frac != null) bossMinFrac = Math.min(bossMinFrac, obs.reward_info.boss_hp_frac);
  }
  return { seed, steps, ri: obs.reward_info, upgrades, bossSeen, bossMaxHp, bossVariant, bossMinFrac, bossPhases };
}

function chooseUpg(options) {
  // heuristic priority by id keyword
  const pri = (o) => {
    const s = (o.id + " " + o.name + " " + o.desc).toLowerCase();
    let p = 0;
    if (/dmg|damage|atk|attack|power|伤害|攻击/.test(s)) p += 5;
    if (/fire|rate|interval|cooldown|攻速|射速|frequency/.test(s)) p += 5;
    if (/pierce|穿透/.test(s)) p += 4;
    if (/side|multi|spread|弹|散/.test(s)) p += 4;
    if (/satellite|orbit|卫星|无人机/.test(s)) p += 3;
    if (/hp|health|生命|护甲|shield|护盾/.test(s)) p += 2;
    const rar = { green: 0, blue: 1, purple: 2, orange: 3 }[o.rarity] || 0;
    return p + rar;
  };
  let best = 0, bp = -1e9;
  options.forEach((o, i) => { const p = pri(o); if (p > bp) { bp = p; best = i; } });
  return best;
}

const seed = Number(process.argv[2] || 1);
const maxSteps = Number(process.argv[3] || 90000);
const res = run(seed, maxSteps, true);
console.log("=== RESULT seed", seed, "===");
console.log("steps:", res.steps, "reason:", res.ri.done_reason, "progress:", res.ri.progress, "score:", res.ri.score);
console.log("level:", res.ri.level, "kills:", res.ri.kills, "wave:", res.ri.wave, "survived_ms:", Math.round(res.ri.survived_ms));
console.log("boss_reached:", res.ri.boss_reached, "boss_cleared:", res.ri.boss_cleared, "boss_hp_destroyed:", res.ri.boss_hp_destroyed);
console.log("bossSeen:", res.bossSeen, "variant:", res.bossVariant, "maxHp:", res.bossMaxHp, "minFrac:", res.bossMinFrac.toFixed(3));
console.log("boss phases:", JSON.stringify(res.bossPhases.slice(0, 20)));
console.log("\n=== ALL UPGRADES SEEN ===");
for (const id in res.upgrades) {
  const u = res.upgrades[id];
  console.log(`  [${u.rarity}] ${u.id} "${u.name}": ${u.desc}`);
}

