"use strict";
const { RogueEnv } = require("./env.bundle.js");

// Measure exp economy: exp values, xp curve, leveling rate.
const env = new RogueEnv();
let { obs } = env.reset(1, { speed_cap: 40, frame_skip: 1, max_steps: 90000 });

// Catalog exp item values
const expValues = {};
let done = false, steps = 0;
const xpCurve = []; // {level, xp_to_next}
let lastLevel = obs.player.level;
xpCurve.push({ level: obs.player.level, xp_to_next: obs.player.xp_to_next });

// track exp collected & level timeline
const levelTimes = [];

// Simple survive+collect policy (reuse explore4-ish but simpler)
function policy(obs) {
  const [px, py] = obs.player.pos;
  const W = obs.field.w, H = obs.field.h;
  const pr = 14;
  const enemies = [], bullets = [], items = [];
  for (const o of obs.objects) {
    if (o.type === "enemy" || o.type === "enemy_elite" || o.type === "boss") enemies.push(o);
    else if (o.type === "enemy_bullet") bullets.push(o);
    else if (o.type === "item") items.push(o);
  }
  const SPEED = 40;
  const cands = [[0, 0]];
  for (let a = 0; a < 24; a++) {
    const ang = (a / 24) * Math.PI * 2;
    cands.push([Math.cos(ang) * SPEED, Math.sin(ang) * SPEED]);
    cands.push([Math.cos(ang) * SPEED * 0.5, Math.sin(ang) * SPEED * 0.5]);
  }
  let killTarget = null, kbest = 1e9;
  for (const e of enemies) {
    if (e.in_cutscene) continue;
    const d = Math.abs(e.pos[0] - px) + Math.max(0, e.pos[1] - py) * 0.15;
    if (d < kbest) { kbest = d; killTarget = e; }
  }
  function score(mv) {
    const nx = Math.max(pr, Math.min(W - pr, px + mv[0]));
    const ny = Math.max(pr, Math.min(H - pr, py + mv[1]));
    let danger = 0;
    for (const b of bullets) {
      for (let t = 1; t <= 20; t += 2) {
        const bx = b.pos[0] + b.vel[0] * t, by = b.pos[1] + b.vel[1] * t;
        const d = Math.hypot(bx - nx, by - ny);
        const hitR = pr + b.size[0] / 2 + 2;
        if (d < hitR + 5) danger += (hitR + 5 - d) * 6 / (1 + t * 0.25);
      }
    }
    for (const e of enemies) {
      for (let t = 0; t <= 20; t += 2) {
        const ex = e.pos[0] + e.vel[0] * t, ey = e.pos[1] + e.vel[1] * t;
        const d = Math.hypot(ex - nx, ey - ny);
        const hitR = pr + e.size[0] / 2;
        if (d < hitR + 12) danger += (hitR + 12 - d) * 30 / (1 + t * 0.2);
      }
    }
    const edge = Math.min(nx - pr, W - pr - nx, ny - pr, H - pr - ny);
    if (edge < 25) danger += (25 - edge) * 4;
    danger += Math.max(0, (H * 0.5) - ny) * 0.6;
