"use strict";
const { RogueEnv } = require("./env.bundle.js");
const surv = require("./surv_policy.js");

const all = {};
const seeds = [1, 11, 23, 42, 57, 88, 101, 137, 199, 256, 314, 451];
for (const seed of seeds) {
  const env = new RogueEnv();
  let { obs } = env.reset(seed, { speed_cap: 40, frame_skip: 1, max_steps: 90000 });
  let done = false, steps = 0, mem = surv.init ? surv.init() : {};
  while (!done && steps < 90000) {
    let out = surv.policy(obs, mem);
    mem = out.mem;
    if (obs.pending_upgrade && obs.pending_upgrade.options.length) {
      for (const opt of obs.pending_upgrade.options) {
        if (!all[opt.id]) all[opt.id] = { rarity: opt.rarity, name: opt.name, desc: opt.desc, count: 0 };
        all[opt.id].count++;
      }
    }
    const r = env.step(out.action);
    obs = r.obs; done = r.done; steps++;
  }
}
const byRar = { green: [], blue: [], purple: [], orange: [] };
for (const id in all) { byRar[all[id].rarity] = byRar[all[id].rarity] || []; byRar[all[id].rarity].push({ id, ...all[id] }); }
for (const rar of ["green", "blue", "purple", "orange"]) {
  console.log(`\n=== ${rar.toUpperCase()} ===`);
  for (const u of (byRar[rar] || []).sort((a, b) => b.count - a.count)) {
    console.log(`  ${u.id} "${u.name}" (x${u.count}): ${u.desc}`);
  }
}
console.log("\nTotal unique upgrades:", Object.keys(all).length);

