"use strict";
/**
 * Roguelike Skies — policy.
 *
 * Strategy (discovered by play):
 *  - Autofire shoots straight UP. Enemies & the boss descend from the top.
 *  - The boss has ~19.4M HP across several layers and parks near the top (x≈180).
 *    Enemies keep spawning during the boss fight, so we farm them for EXP -> levels
 *    -> upgrades -> DPS, and grind the boss down. Winning = destroying the boss.
 *  - Contact with an enemy/boss body is near-instant death; enemy bullets chip ~300.
 *    So: survive first (dodge), stay horizontally aligned with the DPS target to land
 *    shots, scoop up EXP, and pick upgrades that maximize boss DPS (+ enough survival).
 *
 * Movement: sample candidate per-tick displacements, score each by predicted danger
 * (bullets + bodies over a short horizon) minus offensive/pickup reward, pick the best.
 * Upgrades: value table favoring boss-DPS multipliers, with adaptive emergency heals
 * and early EXP weighting.
 */

// ---- upgrade valuation -------------------------------------------------------
// Higher = better. Tuned for "destroy the boss" via DPS + survival.
const UPG_BASE = {
  // orange — game-changers
  tyrant_breaker: 120, // 2x damage vs elite & boss
  bullet_crush: 70,    // bullets destroy enemy bullets (survival)
  bullet_void: 70,
  // direct boss/elite damage
  boss_hunter: 75,
  elite_hunter: 30,
  // multishot / projectile count (DPS + exp farming)
  ms_split_s: 62, ms_split_m: 64, ms_split_l: 66,
  // fire rate
  fr_turbo: 50, fr_basic: 48, fr_cool: 46,
  // damage %
  mix_terminal: 58, // dmg+15% crit+25%
  mix_fire: 50,     // dmg+8% fr+15%
  dmg_m: 46, dmg_s: 40, dmg_l: 50,
  // crit / bullet size
  crit_aim: 36, mix_crit: 40,
  bs_size_s: 30, bs_size_m: 33, bs_size_l: 36,
  // extra damage sources
  sat_orbit: 44, sat_extra: 44,
  pc_pierce: 42,
  kill_pulse_3: 30, kill_pulse: 26,
  // exp / leveling (value boosted while low level)
  exp_basic: 40, exp_smart: 40, exp_huge: 44,
  mag_basic: 22,
  // survival
  timeflow_shield: 60, // slow nearby bullets/enemies — strong survival
  shield_basic: 34,
  heal_overflow: 24, regen_basic: 26,
  kill_blood: 30,      // lifesteal scales with our high DPS
  thorn_static: 12,
  // emergency heal (valued adaptively below)
  heal_quick: 18,
  // utility / weak
  reroll_premium: 28, drop_basic: 14,
  mix_econ: 6, coin_small: 4, coin_big: 6,
};

function keywordValue(s) {
  s = s.toLowerCase();
  let v = 10;
  if (/boss|屠龙|王座/.test(s)) v += 60;
  if (/双倍|double/.test(s)) v += 40;
  if (/伤害|damage|dmg|弹芯|高能/.test(s)) v += 30;
  if (/射速|攻速|急速|fire|rate/.test(s)) v += 30;
  if (/3发|分裂|多重|multi|split|散射/.test(s)) v += 35;
  if (/穿透|pierce/.test(s)) v += 25;
  if (/暴击|crit/.test(s)) v += 22;
  if (/卫星|satellite|orbit/.test(s)) v += 28;
  if (/经验|exp/.test(s)) v += 25;
  if (/护盾|shield|减速|时间流/.test(s)) v += 30;
  if (/回复|修复|治疗|heal|regen|吸血/.test(s)) v += 18;
  if (/弹幕|摧毁.*弹|destroy/.test(s)) v += 40;
  if (/金币|coin|赏金/.test(s)) v -= 5;
  return v;
}

function chooseUpgrade(obs) {
  const opts = obs.pending_upgrade.options;
  const p = obs.player;
  const hpFrac = p.max_hp > 0 ? (p.hp + (p.shield_hp || 0)) / p.max_hp : 1;
  const level = p.level;
  const RAR = { green: 0, blue: 6, purple: 14, orange: 24 };
  let bestIdx = 0, bestVal = -1e9;
  for (let i = 0; i < opts.length; i++) {
    const o = opts[i];
    let val = UPG_BASE[o.id];
    if (val == null) val = keywordValue((o.id || "") + " " + (o.name || "") + " " + (o.desc || ""));
    val += RAR[o.rarity] || 0;
    const idn = o.id || "";
    // Early-game: leveling snowball matters a lot during the long boss grind.
    if (/exp/.test(idn)) val += Math.max(0, 30 - level * 2);
    if (idn === "mag_basic") val += Math.max(0, 15 - level * 1.5);
    // Emergency: prioritize big heals/shields when actually hurt.
    if (hpFrac < 0.45 && /heal_quick|shield_basic|heal_overflow/.test(idn)) val += 90 * (0.6 - hpFrac);
    if (hpFrac > 0.85 && idn === "heal_quick") val -= 15; // wasteful at full hp
    bestVal = val > bestVal ? (bestIdx = i, val) : bestVal;
  }
  return bestIdx;
}

// ---- movement ---------------------------------------------------------------
const SPEED = 40;
// candidate per-tick displacements: stay, plus rings of directions at a few magnitudes
const CANDS = (() => {
  const c = [[0, 0]];
  const mags = [SPEED, SPEED * 0.66, SPEED * 0.33];
  const N = 24;
  for (let a = 0; a < N; a++) {
    const ang = (a / N) * Math.PI * 2, cx = Math.cos(ang), sy = Math.sin(ang);
    for (const m of mags) c.push([cx * m, sy * m]);
  }
  return c;
})();

function decideMove(obs) {
  const [px, py] = obs.player.pos;
  const W = obs.field.w, H = obs.field.h;
  const pr = Math.max(obs.player.size[0], obs.player.size[1]) / 2; // conservative hit radius

  const bullets = [], bodies = [], items = [];
  let boss = null;
  for (const o of obs.objects) {
    switch (o.type) {
      case "enemy_bullet": bullets.push(o); break;
      case "enemy": case "enemy_elite": bodies.push(o); break;
      case "boss": if (!o.in_cutscene) { bodies.push(o); boss = o; } break;
      case "item": items.push(o); break;
    }
  }

  // Primary DPS target for horizontal alignment: boss if present, else nearest enemy.
  let aimTarget = boss;
  if (!aimTarget) {
    let best = 1e9;
    for (const e of bodies) {
      if (e.type === "boss") continue;
      const d = Math.abs(e.pos[0] - px) + Math.max(0, e.pos[1] - py) * 0.12;
      if (d < best) { best = d; aimTarget = e; }
    }
  }

  const HZ = 22; // prediction horizon (ticks)
  function score(mv) {
    const nx = Math.max(pr, Math.min(W - pr, px + mv[0]));
    const ny = Math.max(pr, Math.min(H - pr, py + mv[1]));
    let danger = 0;
    // enemy bullets — predict forward, penalize near-misses
    for (const b of bullets) {
      const bhw = (b.size ? b.size[0] : 6) / 2;
      const hitR = pr + bhw + 2;
      for (let t = 1; t <= HZ; t += 2) {
        const dx = b.pos[0] + b.vel[0] * t - nx, dy = b.pos[1] + b.vel[1] * t - ny;
        const d = Math.hypot(dx, dy);
        if (d < hitR + 8) danger += (hitR + 8 - d) * (8 + (b.dmg || 300) * 0.01) / (1 + t * 0.22);
      }
    }
    // bodies (enemies/boss) — contact is lethal; keep clear
    for (const e of bodies) {
      const ehw = e.size[0] / 2;
      const hitR = pr + ehw;
      for (let t = 0; t <= HZ; t += 2) {
        const dx = e.pos[0] + e.vel[0] * t - nx, dy = e.pos[1] + e.vel[1] * t - ny;
        const d = Math.hypot(dx, dy);
        if (d < hitR + 16) danger += (hitR + 16 - d) * 45 / (1 + t * 0.18);
      }
    }
    // walls
    const edge = Math.min(nx - pr, W - pr - nx, ny - pr, H - pr - ny);
    if (edge < 28) danger += (28 - edge) * 4;
    // prefer a maneuverable lower-middle band; not pinned to the very bottom
    if (ny < H * 0.45) danger += (H * 0.45 - ny) * 0.8;
    if (ny > H * 0.93) danger += (ny - H * 0.93) * 2;

    let reward = 0;
    if (aimTarget) {
      const off = Math.abs(aimTarget.pos[0] - nx);
      // staying aligned to land autofire; flat bonus when well-aligned
      reward += Math.max(0, 60 - off) * 1.6;
    }
    for (const it of items) {
      const d = Math.hypot(it.pos[0] - nx, it.pos[1] - ny);
      if (d < 140) reward += Math.max(0, 140 - d) * 0.45;
    }
    return reward - danger;
  }

  let best = [0, 0], bs = -1e18;
  for (const mv of CANDS) { const s = score(mv); if (s > bs) { bs = s; best = mv; } }
  return best;
}

module.exports = {
  init() { return {}; },
  policy(obs, mem) {
    try {
      if (obs.pending_upgrade && obs.pending_upgrade.options && obs.pending_upgrade.options.length) {
        return { action: { move: [0, 0], upgrade_choice: chooseUpgrade(obs) }, mem };
      }
      return { action: { move: decideMove(obs), upgrade_choice: null }, mem };
    } catch (e) {
      return { action: { move: [0, 0], upgrade_choice: 0 }, mem };
    }
  },
};

