// candidate per-tick displacements: stay, plus rings of directions at a few magnitudes
const CANDS = (() => {
  const c = [[0, 0]];
  const mags = [SPEED, SPEED * 0.66, SPEED * 0.33];
  const N = 24;
  for (let a = 0; a < N; a++) {
    const ang = (a / N) * Math.PI * 2, cx = Math.cos(ang), sy = Math.sin(ang);
    for (const m of mags) c.push([cx * m, sy * m]);
  }
  return c;
})();

function decideMove(obs) {
  const [px, py] = obs.player.pos;
  const W = obs.field.w, H = obs.field.h;
  const pr = Math.max(obs.player.size[0], obs.player.size[1]) / 2; // conservative hit radius

  const bullets = [], bodies = [], items = [];
  let boss = null;
  for (const o of obs.objects) {
    switch (o.type) {
      case "enemy_bullet": bullets.push(o); break;
      case "enemy": case "enemy_elite": bodies.push(o); break;
      case "boss": if (!o.in_cutscene) { bodies.push(o); boss = o; } break;
      case "item": items.push(o); break;
    }
  }

  // Primary DPS target for horizontal alignment: boss if present, else nearest enemy.
  let aimTarget = boss;
  if (!aimTarget) {
    let best = 1e9;
    for (const e of bodies) {
      if (e.type === "boss") continue;
      const d = Math.abs(e.pos[0] - px) + Math.max(0, e.pos[1] - py) * 0.12;
      if (d < best) { best = d; aimTarget = e; }
    }
  }

  const HZ = 22; // prediction horizon (ticks)
  function score(mv) {
    const nx = Math.max(pr, Math.min(W - pr, px + mv[0]));
    const ny = Math.max(pr, Math.min(H - pr, py + mv[1]));
    let danger = 0;
    // enemy bullets — predict forward, penalize near-misses
    for (const b of bullets) {
      const bhw = (b.size ? b.size[0] : 6) / 2;
      const hitR = pr + bhw + 2;
      for (let t = 1; t <= HZ; t += 2) {
        const dx = b.pos[0] + b.vel[0] * t - nx, dy = b.pos[1] + b.vel[1] * t - ny;
        const d = Math.hypot(dx, dy);
        if (d < hitR + 8) danger += (hitR + 8 - d) * (8 + (b.dmg || 300) * 0.01) / (1 + t * 0.22);
      }
    }
    // bodies (enemies/boss) — contact is lethal; keep clear
    for (const e of bodies) {
      const ehw = e.size[0] / 2;
      const hitR = pr + ehw;
      for (let t = 0; t <= HZ; t += 2) {
        const dx = e.pos[0] + e.vel[0] * t - nx, dy = e.pos[1] + e.vel[1] * t - ny;
        const d = Math.hypot(dx, dy);
        if (d < hitR + 16) danger += (hitR + 16 - d) * 45 / (1 + t * 0.18);
      }
    }
    // walls
    const edge = Math.min(nx - pr, W - pr - nx, ny - pr, H - pr - ny);
    if (edge < 28) danger += (28 - edge) * 4;
    // prefer a maneuverable lower-middle band; not pinned to the very bottom
    if (ny < H * 0.45) danger += (H * 0.45 - ny) * 0.8;
    if (ny > H * 0.93) danger += (ny - H * 0.93) * 2;

    let reward = 0;
    if (aimTarget) {
      const off = Math.abs(aimTarget.pos[0] - nx);
      // staying aligned to land autofire; flat bonus when well-aligned
      reward += Math.max(0, 60 - off) * 1.6;
    }
    for (const it of items) {
      const d = Math.hypot(it.pos[0] - nx, it.pos[1] - ny);
      if (d < 140) reward += Math.max(0, 140 - d) * 0.45;
    }
    return reward - danger;
  }

  let best = [0, 0], bs = -1e18;
  for (const mv of CANDS) { const s = score(mv); if (s > bs) { bs = s; best = mv; } }
  return best;
}

module.exports = {
  init() { return {}; },
  policy(obs, mem) {
    try {
      if (obs.pending_upgrade && obs.pending_upgrade.options && obs.pending_upgrade.options.length) {
        return { action: { move: [0, 0], upgrade_choice: chooseUpgrade(obs) }, mem };
      }
      return { action: { move: decideMove(obs), upgrade_choice: null }, mem };
    } catch (e) {
      return { action: { move: [0, 0], upgrade_choice: 0 }, mem };
    }
  },
};

