"use strict";
const { RogueEnv } = require("./env.bundle.js");
const pol = require("./policy.js");

const seed = Number(process.argv[2] || 1);
const env = new RogueEnv();
let { obs } = env.reset(seed, { speed_cap: 40, frame_skip: 1, max_steps: 90000 });
let mem = pol.init ? pol.init() : {};
let done = false, steps = 0;
const hist = [];
let lastHp = obs.player.hp + (obs.player.shield_hp || 0);
while (!done && steps < 90000) {
  const out = pol.policy(obs, mem); mem = out.mem;
  const r = env.step(out.action);
  steps++;
  const eff = r.obs.player.hp + (r.obs.player.shield_hp || 0);
  const boss = r.obs.objects.find(o => o.type === "boss");
  // keep a rolling window
  hist.push({
    step: steps, hp: r.obs.player.hp, sh: r.obs.player.shield_hp, eff,
    ppos: r.obs.player.pos.map(x => +x.toFixed(0)),
    inv: r.obs.player.invincible_ms,
    nbul: r.obs.objects.filter(o => o.type === "enemy_bullet").length,
    nadds: r.obs.objects.filter(o => o.type === "enemy" || o.type === "enemy_elite").length,
    boss: boss ? { y: +boss.pos[1].toFixed(0), cut: boss.in_cutscene, frac: +(boss.hp / boss.max_hp).toFixed(3) } : null,
    drop: eff < lastHp ? lastHp - eff : 0,
  });
  if (hist.length > 120) hist.shift();
  lastHp = eff;
  obs = r.obs; done = r.done;
}
console.log("seed", seed, "died/ended at step", steps, "reason", obs.reward_info.done_reason, "level", obs.player.level, "progress", obs.reward_info.progress);
console.log("last 40 steps before end:");
for (const h of hist.slice(-40)) {
  console.log(`  s${h.step} hp${h.hp}+${h.sh}=${h.eff} ${h.drop ? "DROP-" + h.drop : ""} pos${JSON.stringify(h.ppos)} inv${h.inv} bul${h.nbul} adds${h.nadds} boss${h.boss ? JSON.stringify(h.boss) : "-"}`);
}

