const HZ = 16;
function score(mv) {
  const nx = Math.max(PR, Math.min(W - PR, px + mv[0]));
  const ny = Math.max(PR, Math.min(H - PR, py + mv[1]));
  let threat = 0;

  // enemy bullets: predict forward; squared penalty for being near their path
  for (let i = 0; i < bullets.length; i++) {
    const b = bullets[i];
    const bx0 = b.pos[0], by0 = b.pos[1], vx = b.vel[0], vy = b.vel[1];
    const R = PR + (b.size ? b.size[0] / 2 : 4) + 9; // clearance to keep
    for (let t = 1; t <= HZ; t += 2) {
      const dx = bx0 + vx * t - nx, dy = by0 + vy * t - ny;
      const d2 = dx * dx + dy * dy;
      if (d2 < R * R) {
        const d = Math.sqrt(d2);
        threat += (R - d) * (R - d) * 0.9 / (1 + t * 0.35);
      }
    }
  }
  // bodies: contact is lethal — large clearance, heavy penalty
  for (let i = 0; i < bodies.length; i++) {
    const e = bodies[i];
    const ex0 = e.pos[0], ey0 = e.pos[1], vx = e.vel[0], vy = e.vel[1];
    const R = PR + e.size[0] / 2 + 18;
    for (let t = 0; t <= HZ; t += 2) {
      const dx = ex0 + vx * t - nx, dy = ey0 + vy * t - ny;
      const d2 = dx * dx + dy * dy;
      if (d2 < R * R) {
        const d = Math.sqrt(d2);
        threat += (R - d) * (R - d) * 2.5 / (1 + t * 0.25);
      }
    }
  }
  // edges and corners: rising penalty near a wall; corners (two walls) compound
  const mL = nx - PR, mR = W - PR - nx, mT = ny - PR, mB = H - PR - ny;
  const EDGE = 55;
  if (mL < EDGE) threat += (EDGE - mL) * (EDGE - mL) * 0.06;
  if (mR < EDGE) threat += (EDGE - mR) * (EDGE - mR) * 0.06;
  if (mT < EDGE) threat += (EDGE - mT) * (EDGE - mT) * 0.06;
  if (mB < EDGE) threat += (EDGE - mB) * (EDGE - mB) * 0.10; // bottom wall: extra-bad to hug

  // attraction (gentle — only matters when safe)
  let attract = 0;
  attract -= Math.abs(nx - homeX) * 0.45;
  attract -= Math.abs(ny - homeY) * 0.35;
  if (aimX != null) attract += Math.max(0, 50 - Math.abs(aimX - nx)) * 0.5; // land shots on target
  for (let i = 0; i < items.length; i++) {
    const it = items[i];
    const d = Math.hypot(it.pos[0] - nx, it.pos[1] - ny);
    if (d < 150) attract += (150 - d) * 0.5;
  }
  return attract - threat;
}

