    val += RAR[o.rarity] || 0;
    const idn = o.id || "";
    // Early-game: leveling snowball matters a lot during the long boss grind.
    if (/exp/.test(idn)) val += Math.max(0, 30 - level * 2);
    if (idn === "mag_basic") val += Math.max(0, 15 - level * 1.5);
    // Emergency: prioritize big heals/shields when actually hurt.
