  if (/护盾|shield|减速|时间流/.test(s)) v += 30;
  if (/回复|修复|治疗|heal|regen|吸血/.test(s)) v += 18;
  if (/弹幕|摧毁.*弹|destroy/.test(s)) v += 40;
  if (/金币|coin|赏金/.test(s)) v -= 5;
  return v;
}

function chooseUpgrade(obs) {
  const opts = obs.pending_upgrade.options;
  const p = obs.player;
  const hpFrac = p.max_hp > 0 ? (p.hp + (p.shield_hp || 0)) / p.max_hp : 1;
  const level = p.level;
  const RAR = { green: 0, blue: 6, purple: 14, orange: 24 };
  let bestIdx = 0, bestVal = -1e9;
  for (let i = 0; i < opts.length; i++) {
    const o = opts[i];
    let val = UPG_BASE[o.id];
    if (val == null) val = keywordValue((o.id || "") + " " + (o.name || "") + " " + (o.desc || ""));
    val += RAR[o.rarity] || 0;
    const idn = o.id || "";
    // Early-game: leveling snowball matters a lot during the long boss grind.
    if (/exp/.test(idn)) val += Math.max(0, 30 - level * 2);
    if (idn === "mag_basic") val += Math.max(0, 15 - level * 1.5);
    // Emergency: prioritize big heals/shields when actually hurt.
    if (hpFrac < 0.45 && /heal_quick|shield_basic|heal_overflow/.test(idn)) val += 90 * (0.6 - hpFrac);
    if (hpFrac > 0.85 && idn === "heal_quick") val -= 15; // wasteful at full hp
    bestVal = val > bestVal ? (bestIdx = i, val) : bestVal;
  }
  return bestIdx;
}

// ---- movement (safety-first controller) -------------------------------------
// The player moves up to 40 px/tick; enemy bullets only ~4-5 px/tick — we are ~8x
// faster, so we never need to be hit. We die only by being cornered or touching a
// body. So: keep open space, hug a center-bottom home (x=180 also sits under the
// boss), avoid edges/corners hard, and let safety dominate offense.
const SPEED = 40;
const CANDS = (() => {
  const c = [[0, 0]];
  const N = 32, mags = [SPEED, SPEED * 0.66, SPEED * 0.33];
  for (let a = 0; a < N; a++) {
    const ang = (a / N) * Math.PI * 2, cx = Math.cos(ang), sy = Math.sin(ang);
    for (const m of mags) c.push([cx * m, sy * m]);
  }
  return c;
})();
const PR = 13; // player hit radius (size 24x30 -> ~12-15; conservative)

function decideMove(obs) {
  const [px, py] = obs.player.pos;
  const W = obs.field.w, H = obs.field.h;
  const homeX = W / 2;
  const homeY = H * 0.80;

  const bullets = [], bodies = [], items = [];
  let boss = null;
  for (const o of obs.objects) {
    const ty = o.type;
    if (ty === "enemy_bullet") bullets.push(o);
    else if (ty === "enemy" || ty === "enemy_elite") bodies.push(o);
    else if (ty === "boss") { if (!o.in_cutscene) { bodies.push(o); boss = o; } }
    else if (ty === "item") {
      if (o.item_type && o.item_type.indexOf("exp") === 0) items.push(o);
      else items.push(o); // hearts/bombs/magnet/coin/levelup/invincible: also worth grabbing
    }
  }

  // DPS alignment target: boss if present (sits at center), else nearest add roughly above.
  let aimX = null;
  if (boss) aimX = boss.pos[0];
  else {
    let best = 1e9;
    for (const e of bodies) {
      const d = Math.abs(e.pos[0] - px) + Math.max(0, e.pos[1] - py) * 0.1;
      if (d < best) { best = d; aimX = e.pos[0]; }
    }
  }

  const HZ = 20;
  function score(mv) {
    const nx = Math.max(PR, Math.min(W - PR, px + mv[0]));
    const ny = Math.max(PR, Math.min(H - PR, py + mv[1]));
    let threat = 0;

    // enemy bullets: predict forward; keep a wide clearance. Near-term weighted heavily.
    for (let i = 0; i < bullets.length; i++) {
      const b = bullets[i];
      const bx0 = b.pos[0], by0 = b.pos[1], vx = b.vel[0], vy = b.vel[1];
      const gapR = PR + (b.size ? b.size[0] / 2 : 4); // touching distance
      const SAFE = gapR + 16;                          // want this much clearance
      for (let t = 1; t <= HZ; t++) {
        const dx = bx0 + vx * t - nx, dy = by0 + vy * t - ny;
        const d2 = dx * dx + dy * dy;
        if (d2 < SAFE * SAFE) {
          const d = Math.sqrt(d2);
          const over = SAFE - d;
          let w = 1.4 / (1 + t * 0.3);
          if (d < gapR + 4) w += 30 / (1 + t * 0.5); // about to be hit — strongly avoid
          threat += over * over * w;
        }
      }
    }
    // bodies: contact is lethal — large clearance, heavy penalty
    for (let i = 0; i < bodies.length; i++) {
      const e = bodies[i];
      const ex0 = e.pos[0], ey0 = e.pos[1], vx = e.vel[0], vy = e.vel[1];
      const gapR = PR + e.size[0] / 2;
      const SAFE = gapR + 22;
      for (let t = 0; t <= HZ; t++) {
        const dx = ex0 + vx * t - nx, dy = ey0 + vy * t - ny;
        const d2 = dx * dx + dy * dy;
        if (d2 < SAFE * SAFE) {
          const d = Math.sqrt(d2);
          const over = SAFE - d;
          let w = 3.0 / (1 + t * 0.22);
          if (d < gapR + 6) w += 120 / (1 + t * 0.4); // imminent contact — flee
          threat += over * over * w;
        }
      }
    }
    // edges and corners: rising penalty near a wall; corners (two walls) compound
    const mL = nx - PR, mR = W - PR - nx, mT = ny - PR, mB = H - PR - ny;
    const EDGE = 60;
    if (mL < EDGE) threat += (EDGE - mL) * (EDGE - mL) * 0.09;
    if (mR < EDGE) threat += (EDGE - mR) * (EDGE - mR) * 0.09;
    if (mT < EDGE) threat += (EDGE - mT) * (EDGE - mT) * 0.09;
    if (mB < EDGE) threat += (EDGE - mB) * (EDGE - mB) * 0.14; // bottom wall: extra-bad to hug

    // attraction (gentle — only a tiebreaker; safety dominates)
    let attract = 0;
    attract -= Math.abs(nx - homeX) * 0.18;
    attract -= Math.abs(ny - homeY) * 0.10;
    if (aimX != null) attract += Math.max(0, 55 - Math.abs(aimX - nx)) * 0.35; // land shots on target
    for (let i = 0; i < items.length; i++) {
      const it = items[i];
      const dx = it.pos[0] - nx, dy = it.pos[1] - ny;
      const d = Math.sqrt(dx * dx + dy * dy);
      if (d < 150) attract += (150 - d) * 0.30;
    }
    return attract - threat;
  }

  let best = [0, 0], bs = -1e18;
  for (let i = 0; i < CANDS.length; i++) { const s = score(CANDS[i]); if (s > bs) { bs = s; best = CANDS[i]; } }
  return best;
}

module.exports = {
  init() { return {}; },
  policy(obs, mem) {
    try {
      if (obs.pending_upgrade && obs.pending_upgrade.options && obs.pending_upgrade.options.length) {
        return { action: { move: [0, 0], upgrade_choice: chooseUpgrade(obs) }, mem };
      }
      return { action: { move: decideMove(obs), upgrade_choice: null }, mem };
    } catch (e) {
      return { action: { move: [0, 0], upgrade_choice: 0 }, mem };
    }
  },
};

