"use strict";
// Fast multi-seed evaluator. Usage: node eval.js [seedlist] [maxSteps]
const { RogueEnv } = require("./env.bundle.js");
const path = require("path");
delete require.cache[require.resolve("./policy.js")];
const pol = require("./policy.js");

const seeds = (process.argv[2] || "1,11,23,42,57,88,101,137,199,256").split(",").map(Number);
const maxSteps = Number(process.argv[3] || 90000);

let wins = 0, totalScore = 0;
const rows = [];
for (const seed of seeds) {
  const env = new RogueEnv();
  let { obs } = env.reset(seed, { speed_cap: 40, frame_skip: 1, max_steps: maxSteps });
  let mem = pol.init ? pol.init() : {};
  let done = false, steps = 0, winStep = null, err = null;
  while (!done && steps < maxSteps) {
    let out;
    try { out = pol.policy(obs, mem); } catch (e) { err = String(e.message || e); break; }
    mem = out.mem;
    const r = env.step(out.action);
    obs = r.obs; done = r.done; steps++;
    if (r.event && r.event.kind === "game_over" && r.event.reason === "win") winStep = steps;
  }
  const ri = obs.reward_info;
  const won = ri.done_reason === "win";
  if (won) wins++;
  const escore = won ? 1 + (90000 - winStep) / 90000 : (ri.progress || 0);
  totalScore += escore;
  rows.push({ seed, reason: ri.done_reason, winStep, steps, lvl: ri.level, kills: ri.kills,
    prog: +(ri.progress || 0).toFixed(3), bhd: +((ri.boss_hp_destroyed) || 0).toFixed(3),
    escore: +escore.toFixed(3), err });
}
for (const r of rows) {
  console.log(`seed ${String(r.seed).padStart(4)} | ${r.err ? "ERR " + r.err : (r.reason || "").padEnd(7)} | escore ${String(r.escore).padStart(6)} | win@${r.winStep || "-"} steps ${String(r.steps).padStart(6)} | lvl ${String(r.lvl).padStart(2)} kills ${String(r.kills).padStart(3)} prog ${r.prog} bhd ${r.bhd}`);
}
console.log(`\nWINS: ${wins}/${seeds.length}   mean eval_score: ${(totalScore / seeds.length).toFixed(4)}`);

