  const bullets = [], bodies = [], items = [];
  let boss = null;
  for (const o of obs.objects) {
    const ty = o.type;
    if (ty === "enemy_bullet") bullets.push(o);
    else if (ty === "enemy" || ty === "enemy_elite") bodies.push(o);
    else if (ty === "boss") { if (!o.in_cutscene) { bodies.push(o); boss = o; } }
    else if (ty === "item") {
      if (o.item_type && o.item_type.indexOf("exp") === 0) items.push(o);
      else items.push(o); // hearts/bombs/magnet/coin/levelup/invincible: also worth grabbing
    }
  }

  // DPS alignment target: boss if present (sits at center), else nearest add roughly above.
  let aimX = null;
  if (boss) aimX = boss.pos[0];
  else {
    let best = 1e9;
    for (const e of bodies) {
      const d = Math.abs(e.pos[0] - px) + Math.max(0, e.pos[1] - py) * 0.1;
      if (d < best) { best = d; aimX = e.pos[0]; }
    }
  }
  // Never climb into the descending boss: keep strictly below its body with margin.
  // Dodge horizontally, not upward into it.
  const safeTopY = boss ? boss.pos[1] + boss.size[1] / 2 + 55 : H * 0.34;

  const HZ = 12;
  function score(mv) {
    const nx = Math.max(PR, Math.min(W - PR, px + mv[0]));
    const ny = Math.max(PR, Math.min(H - PR, py + mv[1]));
    let threat = 0;

    // DANGER HIERARCHY (worst -> least):
    //  1. body contact (boss/enemy) = instant death        -> 1e6 (never)
    //  2. getting cornered/wall-trapped = leads to death    -> steep wall barrier
    //  3. eating a bullet (~450 dmg, recoverable w/ sustain) -> moderate
    // So we sharp-dodge bullets when we can, but we'd rather EAT a bullet than herd
    // ourselves into a corner or into the boss.
    const WANT_B = 15;
    for (let i = 0; i < bullets.length; i++) {
      const b = bullets[i];
      const bx0 = b.pos[0], by0 = b.pos[1], vx = b.vel[0], vy = b.vel[1];
      const gapR = PR + (b.size ? b.size[0] / 2 : 4);
      for (let t = 1; t <= HZ; t++) {
        const dx = bx0 + vx * t - nx, dy = by0 + vy * t - ny;
        const d = Math.sqrt(dx * dx + dy * dy);
        const clear = d - gapR;
        if (clear < WANT_B) {
          const u = 1 / (1 + t * 0.5);
          if (clear <= 2) threat += 750 * u;            // predicted hit — dodge, but survivable
          else threat += (WANT_B - clear) * (WANT_B - clear) * 1.2 * u;
        }
      }
    }
    // bodies: contact is lethal — large clearance, near-absolute penalty
    const WANT_E = 26;
    for (let i = 0; i < bodies.length; i++) {
      const e = bodies[i];
      const ex0 = e.pos[0], ey0 = e.pos[1], vx = e.vel[0], vy = e.vel[1];
      const gapR = PR + e.size[0] / 2;
      for (let t = 0; t <= HZ; t++) {
        const dx = ex0 + vx * t - nx, dy = ey0 + vy * t - ny;
        const d = Math.sqrt(dx * dx + dy * dy);
        const clear = d - gapR;
        if (clear < WANT_E) {
          const u = 1 / (1 + t * 0.35);
          if (clear <= 5) threat += 1e6 * u;           // contact is instant death — forbid
          else threat += (WANT_E - clear) * (WANT_E - clear) * 10.0 * u;
        }
      }
    }
