"use strict";
const { RogueEnv } = require("./env.bundle.js");
delete require.cache[require.resolve("./policy.js")];
const pol = require("./policy.js");

const seeds = (process.argv[2] || "1,23,57,101,199,256,88").split(",").map(Number);
for (const seed of seeds) {
  const env = new RogueEnv();
  let { obs } = env.reset(seed, { speed_cap: 40, frame_skip: 1, max_steps: 90000 });
  let mem = pol.init ? pol.init() : {};
  let done = false, steps = 0;
  let prev = obs, lastEff = obs.player.hp;
  let cause = "?", info = "";
  while (!done && steps < 90000) {
    const out = pol.policy(obs, mem); mem = out.mem;
    const r = env.step(out.action); steps++;
    const eff = r.obs.player.hp + (r.obs.player.shield_hp || 0);
    if (eff <= 0 && lastEff > 0) {
      // classify death: examine prev obs (before fatal step)
      const [px, py] = prev.player.pos;
      const W = prev.field.w, H = prev.field.h;
      const drop = lastEff;
      // nearest body & bullet
      let nb = null, nbd = 1e9, nbody = null, nbodyd = 1e9;
      for (const o of prev.objects) {
        const d = Math.hypot(o.pos[0] - px, o.pos[1] - py);
        if (o.type === "enemy_bullet" && d < nbd) { nbd = d; nb = o; }
        if ((o.type === "enemy" || o.type === "enemy_elite" || o.type === "boss") && (d - o.size[0] / 2) < nbodyd) { nbodyd = d - o.size[0] / 2; nbody = o; }
      }
      const mH = Math.min(px, W - px), mV = Math.min(py, H - py);
      const corner = (mH < 55 && mV < 80);
      const nbullets = prev.objects.filter(o => o.type === "enemy_bullet").length;
      if (drop > 1500 && nbody && nbodyd < 30) cause = "BODY(" + nbody.type + "/" + (nbody.enemy_type || nbody.variant) + " gap" + nbodyd.toFixed(0) + ")";
      else if (corner) cause = "CORNER-chip";
      else cause = "CHIP";
      info = `pos[${px.toFixed(0)},${py.toFixed(0)}] mH${mH.toFixed(0)} mV${mV.toFixed(0)} drop${drop} nbul${nbullets} nbodyGap${nbodyd.toFixed(0)}`;
      break;
    }
    lastEff = eff; prev = r.obs; obs = r.obs; done = r.done;
  }
  const ri = obs.reward_info;
  console.log(`seed ${String(seed).padStart(4)} | ${(ri.done_reason||"").padEnd(7)} step ${String(steps).padStart(6)} lvl ${String(ri.level).padStart(2)} | ${cause.padEnd(28)} ${info}`);
}

