"use strict";
/**
 * Roguelike Skies — policy.
 *
 * Strategy (discovered by play):
 *  - Autofire shoots straight UP. Enemies & the boss descend from the top.
 *  - The boss has ~19.4M HP across several layers and parks near the top (x≈180).
 *    Enemies keep spawning during the boss fight, so we farm them for EXP -> levels
 *    -> upgrades -> DPS, and grind the boss down. Winning = destroying the boss.
 *  - Contact with an enemy/boss body is near-instant death; enemy bullets chip ~300.
 *    So: survive first (dodge), stay horizontally aligned with the DPS target to land
 *    shots, scoop up EXP, and pick upgrades that maximize boss DPS (+ enough survival).
 *
 * Movement: sample candidate per-tick displacements, score each by predicted danger
 * (bullets + bodies over a short horizon) minus offensive/pickup reward, pick the best.
 * Upgrades: value table favoring boss-DPS multipliers, with adaptive emergency heals
 * and early EXP weighting.
 */

// ---- upgrade valuation -------------------------------------------------------
// Survival is the binding constraint: surviving the long boss grind ~guarantees a win
// (DPS from leveling is more than enough to kill it within the step budget). So value
// sustain/defense highly, take EXP early to snowball, and keep enough offense.
const UPG_BASE = {
  // defensive game-changers
  bullet_crush: 100,    // your bullets destroy enemy bullets — huge incoming-fire cut
  bullet_void: 100,
  timeflow_shield: 92,  // slow nearby bullets/enemies 50% — trivializes dodging
  // sustain (keeps us alive over a 50k-step fight)
  kill_blood: 72,       // lifesteal — scales with our enormous DPS
  shield_basic: 70,     // shield = max_hp, auto-repairs 3%/s
  regen_basic: 62,      // 1%/s base hp
  heal_overflow: 40,    // overheal -> shield
  // direct boss damage (cheap win-speed; safe to take)
  boss_hunter: 70, tyrant_breaker: 96, // 2x vs elite & boss (also great)
  elite_hunter: 28,
  // multishot / projectile count (DPS + add-clear -> exp + lifesteal procs)
  ms_split_s: 58, ms_split_m: 60, ms_split_l: 62,
  // fire rate / damage
  fr_turbo: 50, fr_basic: 48, fr_cool: 46,
  mix_terminal: 56, mix_fire: 52, dmg_m: 46, dmg_s: 42, dmg_l: 50,
  crit_aim: 38, mix_crit: 42,
  bs_size_s: 32, bs_size_m: 35, bs_size_l: 38,
  sat_orbit: 48, sat_extra: 48,
  pc_pierce: 46,
  kill_pulse_3: 34, kill_pulse: 28,
  // exp / leveling (value boosted while low level, below)
  exp_basic: 44, exp_smart: 44, exp_huge: 48,
  mag_basic: 30,
  thorn_static: 14,
  heal_quick: 22,       // valued adaptively when hurt
  reroll_premium: 40, drop_basic: 16,
  mix_econ: 6, coin_small: 4, coin_big: 6,
};

function keywordValue(s) {
  s = s.toLowerCase();
  let v = 20;
  if (/弹幕|摧毁.*弹|destroy.*bullet|无坚不摧/.test(s)) v += 70;
  if (/减速|时间流|slow/.test(s)) v += 60;
  if (/护盾|shield/.test(s)) v += 45;
  if (/回复|修复|治疗|heal|regen|吸血|lifesteal/.test(s)) v += 45;
  if (/boss|屠龙|王座/.test(s)) v += 45;
  if (/双倍|double/.test(s)) v += 35;
  if (/3发|分裂|多重|multi|split|散射/.test(s)) v += 32;
  if (/射速|攻速|急速|fire|rate/.test(s)) v += 28;
  if (/伤害|damage|dmg|弹芯|高能/.test(s)) v += 26;
  if (/卫星|satellite|orbit/.test(s)) v += 26;
  if (/穿透|pierce/.test(s)) v += 24;
  if (/暴击|crit/.test(s)) v += 20;
  if (/经验|exp/.test(s)) v += 24;
  if (/金币|coin|赏金/.test(s)) v -= 8;
  return v;
}

function chooseUpgrade(obs) {
  const opts = obs.pending_upgrade.options;
  const p = obs.player;
  const hpFrac = p.max_hp > 0 ? (p.hp + (p.shield_hp || 0)) / p.max_hp : 1;
  const level = p.level;
  const RAR = { green: 0, blue: 5, purple: 12, orange: 22 };
  let bestIdx = 0, bestVal = -1e9;
  for (let i = 0; i < opts.length; i++) {
    const o = opts[i];
    let val = UPG_BASE[o.id];
    if (val == null) val = keywordValue((o.id || "") + " " + (o.name || "") + " " + (o.desc || ""));
    val += RAR[o.rarity] || 0;
    const idn = o.id || "";
    // Early-game: leveling snowball matters a lot during the long boss grind.
    if (/exp/.test(idn)) val += Math.max(0, 34 - level * 2.2);
    if (idn === "mag_basic") val += Math.max(0, 18 - level * 1.5);
    // Sustain becomes even more valuable as the fight drags on / DPS climbs.
    if (idn === "kill_blood") val += Math.min(20, level * 1.0);
    // Emergency: prioritize big heals/shields when actually hurt.
    if (hpFrac < 0.5 && /heal_quick|shield_basic|heal_overflow|regen_basic/.test(idn)) val += 120 * (0.6 - hpFrac);
    if (hpFrac > 0.85 && idn === "heal_quick") val -= 18; // wasteful at full hp
    if (val > bestVal) { bestVal = val; bestIdx = i; }
  }
  return bestIdx;
}

// ---- movement (safety-first controller) -------------------------------------
// The player moves up to 40 px/tick; enemy bullets only ~4-5 px/tick — we are ~8x
// faster, so we never need to be hit. We die only by being cornered or touching a
// body. So: keep open space, hug a center-bottom home (x=180 also sits under the
// boss), avoid edges/corners hard, and let safety dominate offense.
const SPEED = 40;
const CANDS = (() => {
  const c = [[0, 0]];
  const N = 32, mags = [SPEED, SPEED * 0.66, SPEED * 0.33];
  for (let a = 0; a < N; a++) {
    const ang = (a / N) * Math.PI * 2, cx = Math.cos(ang), sy = Math.sin(ang);
    for (const m of mags) c.push([cx * m, sy * m]);
  }
  return c;
})();
const PR = 13; // player hit radius (size 24x30 -> ~12-15; conservative)

function decideMove(obs) {
  const [px, py] = obs.player.pos;
  const W = obs.field.w, H = obs.field.h;
  const homeX = W / 2;
  const homeY = H * 0.70; // middle-low band: vertical escape room both ways (NOT pinned to the bottom wall)

  const bullets = [], bodies = [], items = [];
  let boss = null;
  for (const o of obs.objects) {
    const ty = o.type;
    if (ty === "enemy_bullet") bullets.push(o);
    else if (ty === "enemy" || ty === "enemy_elite") bodies.push(o);
    else if (ty === "boss") { if (!o.in_cutscene) { bodies.push(o); boss = o; } }
    else if (ty === "item") {
      if (o.item_type && o.item_type.indexOf("exp") === 0) items.push(o);
      else items.push(o); // hearts/bombs/magnet/coin/levelup/invincible: also worth grabbing
    }
  }

  // DPS alignment target: boss if present (sits at center), else nearest add roughly above.
  let aimX = null;
  if (boss) aimX = boss.pos[0];
  else {
    let best = 1e9;
    for (const e of bodies) {
      const d = Math.abs(e.pos[0] - px) + Math.max(0, e.pos[1] - py) * 0.1;
      if (d < best) { best = d; aimX = e.pos[0]; }
    }
  }
  // Never climb into the descending boss: keep strictly below its body with margin.
  // Dodge horizontally, not upward into it.
  const safeTopY = boss ? boss.pos[1] + boss.size[1] / 2 + 55 : H * 0.34;

  const HZ = 12;
  function score(mv) {
    const nx = Math.max(PR, Math.min(W - PR, px + mv[0]));
    const ny = Math.max(PR, Math.min(H - PR, py + mv[1]));
    let threat = 0;

    // DANGER HIERARCHY (worst -> least): body contact (instant death) >> corner-trap
    // (leads to death) >> eating a bullet (~450 dmg, recoverable with sustain). We
    // sharp-dodge bullets, but would rather eat one than herd into a corner/boss.
    const WANT_B = 15;
    for (let i = 0; i < bullets.length; i++) {
      const b = bullets[i];
      const bx0 = b.pos[0], by0 = b.pos[1], vx = b.vel[0], vy = b.vel[1];
      const gapR = PR + (b.size ? b.size[0] / 2 : 4);
      for (let t = 1; t <= HZ; t++) {
        const dx = bx0 + vx * t - nx, dy = by0 + vy * t - ny;
        const d = Math.sqrt(dx * dx + dy * dy);
        const clear = d - gapR;
        if (clear < WANT_B) {
          const u = 1 / (1 + t * 0.5);
          if (clear <= 2) threat += 1600 * u;
          else threat += (WANT_B - clear) * (WANT_B - clear) * 1.7 * u;
        }
      }
    }
    // bodies: contact is lethal — large clearance, near-absolute penalty
    const WANT_E = 26;
    for (let i = 0; i < bodies.length; i++) {
      const e = bodies[i];
      const ex0 = e.pos[0], ey0 = e.pos[1], vx = e.vel[0], vy = e.vel[1];
      const gapR = PR + e.size[0] / 2;
      for (let t = 0; t <= HZ; t++) {
        const dx = ex0 + vx * t - nx, dy = ey0 + vy * t - ny;
        const d = Math.sqrt(dx * dx + dy * dy);
        const clear = d - gapR;
        if (clear < WANT_E) {
          const u = 1 / (1 + t * 0.35);
          if (clear <= 5) threat += 1e6 * u;
          else threat += (WANT_E - clear) * (WANT_E - clear) * 10.0 * u;
        }
      }
    }
    // stay below the boss (climbing toward it is fatal)
    if (ny < safeTopY) threat += (safeTopY - ny) * (safeTopY - ny) * 0.7;
    // walls; corners (near two walls at once) are the death-traps -> extra penalty.
    const mL = nx - PR, mR = W - PR - nx, mT = ny - PR, mB = H - PR - ny;
    const EDGE = 50;
    if (mL < EDGE) threat += (EDGE - mL) * (EDGE - mL) * 0.22;
    if (mR < EDGE) threat += (EDGE - mR) * (EDGE - mR) * 0.22;
    if (mT < EDGE) threat += (EDGE - mT) * (EDGE - mT) * 0.22;
    if (mB < EDGE) threat += (EDGE - mB) * (EDGE - mB) * 0.30;
    const mH = Math.min(mL, mR), mV = Math.min(mT, mB);
    if (mH < 70 && mV < 110) threat += (70 - mH) * (110 - mV) * 0.5; // corner zone

    // hold a bottom-center home (proactive anti-herding), but roam to collect EXP.
    let attract = 0;
    attract -= Math.abs(nx - homeX) * 0.22;
    attract -= Math.abs(ny - homeY) * 0.10;
    if (aimX != null) attract += Math.max(0, 55 - Math.abs(aimX - nx)) * 0.40; // land shots on target
    for (let i = 0; i < items.length; i++) {
      const it = items[i];
      const dx = it.pos[0] - nx, dy = it.pos[1] - ny;
      const d = Math.sqrt(dx * dx + dy * dy);
      if (d < 170) attract += (170 - d) * 0.55; // sweep up falling EXP (drives leveling)
    }
    return attract - threat;
  }

  let best = [0, 0], bs = -1e18;
  for (let i = 0; i < CANDS.length; i++) { const s = score(CANDS[i]); if (s > bs) { bs = s; best = CANDS[i]; } }
  return best;
}

module.exports = {
  init() { return {}; },
  policy(obs, mem) {
    try {
      if (obs.pending_upgrade && obs.pending_upgrade.options && obs.pending_upgrade.options.length) {
        return { action: { move: [0, 0], upgrade_choice: chooseUpgrade(obs) }, mem };
      }
      return { action: { move: decideMove(obs), upgrade_choice: null }, mem };
    } catch (e) {
      return { action: { move: [0, 0], upgrade_choice: 0 }, mem };
    }
  },
};

