    if (/exp/.test(idn)) val += Math.max(0, 34 - level * 2.2);
    if (idn === "mag_basic") val += Math.max(0, 18 - level * 1.5);
    // Sustain becomes even more valuable as the fight drags on / DPS climbs.
    if (idn === "kill_blood") val += Math.min(20, level * 1.0);
