const PR = 13; // player hit radius (size 24x30 -> ~12-15; conservative)
const ROLL = 7; // ballistic rollout horizon (ticks)

function decideMove(obs) {
  const [px, py] = obs.player.pos;
  const W = obs.field.w, H = obs.field.h;
  const homeX = W / 2;
  const homeY = H * 0.72; // middle-low band: vertical escape room both ways (not pinned low)

  // flat arrays for speed
  const bx = [], by = [], bvx = [], bvy = [], br = [];
  const ex = [], ey = [], evx = [], evy = [], er = [];
  const items = [];
  let boss = null;
  for (const o of obs.objects) {
    const ty = o.type;
    if (ty === "enemy_bullet") { bx.push(o.pos[0]); by.push(o.pos[1]); bvx.push(o.vel[0]); bvy.push(o.vel[1]); br.push(PR + (o.size ? o.size[0] / 2 : 4)); }
    else if (ty === "enemy" || ty === "enemy_elite") { ex.push(o.pos[0]); ey.push(o.pos[1]); evx.push(o.vel[0]); evy.push(o.vel[1]); er.push(PR + o.size[0] / 2); }
    else if (ty === "boss") { if (!o.in_cutscene) { ex.push(o.pos[0]); ey.push(o.pos[1]); evx.push(o.vel[0]); evy.push(o.vel[1]); er.push(PR + o.size[0] / 2); boss = o; } }
    else if (ty === "item") items.push(o);
