  let aimX = null;
  if (boss) aimX = boss.pos[0];
  else {
    let best = 1e9;
    for (let i = 0; i < NE; i++) {
      const d = Math.abs(ex[i] - px) + Math.max(0, ey[i] - py) * 0.1;
      if (d < best) { best = d; aimX = ex[i]; }
    }
  }
  // never climb into the descending boss; stay below its body with margin
  const safeTopY = boss ? boss.pos[1] + boss.size[1] / 2 + 55 : H * 0.30;

  function score(mv) {
    const vx = mv[0], vy = mv[1];
    let threat = 0;
    // ballistic rollout
    for (let t = 1; t <= ROLL; t++) {
      let nx = px + vx * t, ny = py + vy * t;
      if (nx < PR) nx = PR; else if (nx > W - PR) nx = W - PR;
      if (ny < PR) ny = PR; else if (ny > H - PR) ny = H - PR;
      const td = 1 / (1 + (t - 1) * 0.55); // near-term weighted most
      // bullets
      for (let i = 0; i < NB; i++) {
        const dx = bx[i] + bvx[i] * t - nx, dy = by[i] + bvy[i] * t - ny;
        const clear = Math.sqrt(dx * dx + dy * dy) - br[i];
        if (clear < 15) {
          if (clear <= 2) threat += 1600 * td;
          else threat += (15 - clear) * (15 - clear) * 1.7 * td;
        }
      }
      // bodies — contact is instant death
      for (let i = 0; i < NE; i++) {
        const dx = ex[i] + evx[i] * t - nx, dy = ey[i] + evy[i] * t - ny;
        const clear = Math.sqrt(dx * dx + dy * dy) - er[i];
        if (clear < 26) {
          if (clear <= 5) threat += 1e6 * td;
          else threat += (26 - clear) * (26 - clear) * 10.0 * td;
        }
      }
      // stay below boss
      if (ny < safeTopY) threat += (safeTopY - ny) * (safeTopY - ny) * 0.7 * td;
