      if (mH < 70 && mV < 110) threat += (70 - mH) * (110 - mV) * 0.5 * td;
    }

    // attraction evaluated at the immediate (t=1) position we actually move to
    let ax = px + vx, ay = py + vy;
    if (ax < PR) ax = PR; else if (ax > W - PR) ax = W - PR;
    if (ay < PR) ay = PR; else if (ay > H - PR) ay = H - PR;
