      const mL = nx - PR, mR = W - PR - nx, mT = ny - PR, mB = H - PR - ny;
      const EDGE = 50;
      if (mL < EDGE) threat += (EDGE - mL) * (EDGE - mL) * 0.22 * td;
      if (mR < EDGE) threat += (EDGE - mR) * (EDGE - mR) * 0.22 * td;
      if (mT < EDGE) threat += (EDGE - mT) * (EDGE - mT) * 0.22 * td;
      if (mB < EDGE) threat += (EDGE - mB) * (EDGE - mB) * 0.30 * td;
      if (ny > H * 0.82) threat += (ny - H * 0.82) * (ny - H * 0.82) * 0.5 * td;
      const mH = mL < mR ? mL : mR, mV = mT < mB ? mT : mB;
      if (mH < 70 && mV < 110) threat += (70 - mH) * (110 - mV) * 0.5 * td;
    }

    // attraction evaluated at the immediate (t=1) position we actually move to
    let ax = px + vx, ay = py + vy;
    if (ax < PR) ax = PR; else if (ax > W - PR) ax = W - PR;
    if (ay < PR) ay = PR; else if (ay > H - PR) ay = H - PR;
    let attract = 0;
    attract -= Math.abs(ax - homeX) * 0.22;
    attract -= Math.abs(ay - homeY) * 0.10;
    if (aimX != null) attract += Math.max(0, 55 - Math.abs(aimX - ax)) * 0.40;
    for (let i = 0; i < items.length; i++) {
      const it = items[i];
      if (it.pos[1] > ay + 50) continue; // don't dive downward chasing falling EXP
      const dx = it.pos[0] - ax, dy = it.pos[1] - ay;
      const d = Math.sqrt(dx * dx + dy * dy);
      if (d < 170) attract += (170 - d) * 0.5;
    }
    return attract - threat;
  }

  let best = [0, 0], bs = -1e18;
  for (let i = 0; i < CANDS.length; i++) { const s = score(CANDS[i]); if (s > bs) { bs = s; best = CANDS[i]; } }
  return best;
}

