  }
  return c;
})();
const PR = 13; // player hit radius (size 24x30 -> ~12-15; conservative)
const ROLL = 7; // ballistic rollout horizon (ticks)

function decideMove(obs) {
  const [px, py] = obs.player.pos;
  const W = obs.field.w, H = obs.field.h;
  const homeX = W / 2;
  const homeY = H * 0.72; // middle-low band: vertical escape room both ways (not pinned low)

