    for (let t = 1; t <= ROLL; t++) {
      let nx = px + vx * t, ny = py + vy * t;
      if (nx < PR) nx = PR; else if (nx > W - PR) nx = W - PR;
      if (ny < PR) ny = PR; else if (ny > H - PR) ny = H - PR;
      const td = 1 / (1 + (t - 1) * 0.55); // near-term weighted most
      // bullets
      for (let i = 0; i < NB; i++) {
