      if (d < expRange) attract += (expRange - d) * expW;
    }
    return attract - threat;
  }

  let best = [0, 0], bs = -1e18;
  for (let i = 0; i < CANDS.length; i++) { const s = score(CANDS[i]); if (s > bs) { bs = s; best = CANDS[i]; } }
  return best;
}

module.exports = {
  init() { return { picks: {} }; },
  policy(obs, mem) {
    if (!mem || typeof mem !== "object") mem = { picks: {} };
