"use strict";
// Measure how often, during the boss, the player has NO hit-free move (forced hit)
// vs. an avoidable hit. Reconstruct candidate set like the policy.
const { RogueEnv } = require("./env.bundle.js");
const pol = require("./policy.js");

const PR = 13, SPEED = 40;
const CANDS = (() => {
  const c = [[0, 0]];
  for (let a = 0; a < 48; a++) { const ang = a / 48 * Math.PI * 2; c.push([Math.cos(ang) * SPEED, Math.sin(ang) * SPEED]); c.push([Math.cos(ang) * SPEED * 0.6, Math.sin(ang) * SPEED * 0.6]); c.push([Math.cos(ang) * SPEED * 0.3, Math.sin(ang) * SPEED * 0.3]); }
  return c;
})();

function existsHitFree(obs) {
  const [px, py] = obs.player.pos, W = obs.field.w, H = obs.field.h;
  const bs = obs.objects.filter(o => o.type === "enemy_bullet");
  const bodies = obs.objects.filter(o => o.type === "enemy" || o.type === "enemy_elite" || (o.type === "boss" && !o.in_cutscene));
  let hitFree = 0, anyFree = false;
  for (const mv of CANDS) {
    let nx = px + mv[0], ny = py + mv[1];
    if (nx < PR) nx = PR; else if (nx > W - PR) nx = W - PR;
    if (ny < PR) ny = PR; else if (ny > H - PR) ny = H - PR;
    let hit = false;
    // check t=1..3 collisions (the imminent window)
    for (let t = 1; t <= 3 && !hit; t++) {
      for (const b of bs) { const dx = b.pos[0] + b.vel[0] * t - nx, dy = b.pos[1] + b.vel[1] * t - ny; if (dx * dx + dy * dy < (PR + b.size[0] / 2) * (PR + b.size[0] / 2)) { hit = true; break; } }
      for (const e of bodies) { const dx = e.pos[0] + e.vel[0] * t - nx, dy = e.pos[1] + e.vel[1] * t - ny; if (dx * dx + dy * dy < (PR + e.size[0] / 2) * (PR + e.size[0] / 2)) { hit = true; break; } }
    }
    if (!hit) { anyFree = true; hitFree++; }
  }
  return { anyFree, hitFreeCount: hitFree, total: CANDS.length };
}

for (const seed of (process.argv[2] || "57,1,23").split(",").map(Number)) {
  const env = new RogueEnv();
  let { obs } = env.reset(seed, { speed_cap: 40, frame_skip: 1, max_steps: 90000 });
  let mem = pol.init(), done = false, steps = 0;
  let bossSteps = 0, forcedSteps = 0, lastHp = obs.player.hp, hits = 0, hitsWhileFree = 0;
  while (!done && steps < 90000) {
    const boss = obs.objects.some(o => o.type === "boss");
    let freeInfo = null;
    if (boss) freeInfo = existsHitFree(obs);
    const out = pol.policy(obs, mem); mem = out.mem;
    const r = env.step(out.action); steps++;
    const eff = r.obs.player.hp + (r.obs.player.shield_hp || 0);
    if (boss) {
      bossSteps++;
      if (!freeInfo.anyFree) forcedSteps++;
      if (eff < lastHp) { hits++; if (freeInfo.anyFree) hitsWhileFree++; }
    }
    lastHp = eff; obs = r.obs; done = r.done;
  }
  console.log(`seed ${seed} ${(obs.reward_info.done_reason||"").padEnd(7)} bossSteps ${bossSteps} | forced(no hit-free move) ${forcedSteps} (${(100*forcedSteps/Math.max(1,bossSteps)).toFixed(1)}%) | damage-events ${hits}, of which ${hitsWhileFree} happened WHILE a hit-free move existed`);
}

