    if (mB < EDGE) threat += (EDGE - mB) * (EDGE - mB) * 0.30 * td;
    if (ny > H * 0.82) threat += (ny - H * 0.82) * (ny - H * 0.82) * 0.5 * td;
    const mH = mL < mR ? mL : mR, mV = mT < mB ? mT : mB;
