  // falling EXP while dodging) — going fully passive starves us of sustain/DPS and we
  // chip out. So even in boss mode keep meaningful EXP pull; threats still dominate.
  const safe = !boss && NB < 10;
  const homeW = safe ? 0.05 : 0.22;
  const alignW = safe ? 1.1 : 0.40, alignRange = safe ? 75 : 55;
  const expW = safe ? 0.85 : 0.5, expRange = safe ? 230 : 170, expBelow = safe ? 260 : 50;
  const useHomeY = safe ? H * 0.62 : H * 0.72;

