  const N = 32, mags = [SPEED, SPEED * 0.72, SPEED * 0.45, SPEED * 0.22];
  for (let a = 0; a < N; a++) {
    const ang = (a / N) * Math.PI * 2, cx = Math.cos(ang), sy = Math.sin(ang);
