    const ty = o.type;
    if (ty === "enemy_bullet") { bx.push(o.pos[0]); by.push(o.pos[1]); bvx.push(o.vel[0]); bvy.push(o.vel[1]); br.push(PR + (o.size ? o.size[0] / 2 : 4)); }
    else if (ty === "enemy" || ty === "enemy_elite") { ex.push(o.pos[0]); ey.push(o.pos[1]); evx.push(o.vel[0]); evy.push(o.vel[1]); er.push(PR + o.size[0] / 2); }
