  const alignW = safe ? 1.1 : 0.40, alignRange = safe ? 75 : 55;
  const expW = safe ? 0.85 : 0.62, expRange = safe ? 230 : 190, expBelow = safe ? 260 : 85;
  const useHomeY = safe ? H * 0.62 : H * 0.72;

  function score(mv) {
    // Static-position safety: we move to P this tick; assess whether HOLDING at P is
    // safe over the next K ticks (we re-plan every tick, so "hold" is the right model
    // for a position's safety — and it matches where hit-free moves actually exist).
    let nx = px + mv[0], ny = py + mv[1];
    if (nx < PR) nx = PR; else if (nx > W - PR) nx = W - PR;
    if (ny < PR) ny = PR; else if (ny > H - PR) ny = H - PR;
    let threat = 0;

    // bullets: a REAL hit dominates (never take an avoidable hit); near-misses give a
    // small, capped tie-break toward roomier spots. Count each bullet's first hit only.
    for (let i = 0; i < NB; i++) {
      const bx0 = bx[i], by0 = by[i], vx = bvx[i], vy = bvy[i], gr = br[i];
      let near = 0;
      for (let t = 1; t <= ROLL; t++) {
        const dx = bx0 + vx * t - nx, dy = by0 + vy * t - ny;
        const clear = Math.sqrt(dx * dx + dy * dy) - gr;
        if (clear <= 3) { threat += 9000 / (1 + (t - 1) * 0.45); near = 0; break; }
        if (clear < 16) { const p = (16 - clear) * 3.0 / (1 + (t - 1) * 0.5); if (p > near) near = p; }
      }
      threat += near;
    }
    // bodies — contact is instant death; assess hold-at-P over the horizon
    for (let i = 0; i < NE; i++) {
      const ex0 = ex[i], ey0 = ey[i], vx = evx[i], vy = evy[i], gr = er[i];
      for (let t = 0; t <= ROLL; t++) {
        const dx = ex0 + vx * t - nx, dy = ey0 + vy * t - ny;
        const clear = Math.sqrt(dx * dx + dy * dy) - gr;
        if (clear <= 5) { threat += 1e6 / (1 + t * 0.3); break; }
        if (clear < 26) threat += (26 - clear) * (26 - clear) * 6.0 / (1 + t * 0.4);
      }
    }
    // stay below boss
    if (ny < safeTopY) threat += (safeTopY - ny) * (safeTopY - ny) * 0.7;
