"use strict";
const { RogueEnv } = require("./env.bundle.js");
const pol = require("./policy.js");
const PR = 13, SPEED = 40;
// EXACT replica of policy's candidate set
const CANDS = (() => {
  const c = [[0, 0]];
  const N = 32, mags = [SPEED, SPEED * 0.72, SPEED * 0.45, SPEED * 0.22];
  for (let a = 0; a < N; a++) { const ang = a / N * Math.PI * 2, cx = Math.cos(ang), sy = Math.sin(ang); for (const m of mags) c.push([cx * m, sy * m]); }
  return c;
})();
function t1hit(obs, mv) {
  const [px, py] = obs.player.pos, W = obs.field.w, H = obs.field.h;
  let nx = px + mv[0], ny = py + mv[1];
  if (nx < PR) nx = PR; else if (nx > W - PR) nx = W - PR;
  if (ny < PR) ny = PR; else if (ny > H - PR) ny = H - PR;
  for (const o of obs.objects) {
    if (o.type === "enemy_bullet") { for (let t = 1; t <= 2; t++) { const dx = o.pos[0] + o.vel[0] * t - nx, dy = o.pos[1] + o.vel[1] * t - ny; if (Math.hypot(dx, dy) < PR + o.size[0] / 2) return true; } }
  }
  return false;
}
function anyHitFreeInMySet(obs) {
  let n = 0; for (const mv of CANDS) if (!t1hit(obs, mv)) n++; return n;
}

const seed = Number(process.argv[2] || 7);
const env = new RogueEnv();
let { obs } = env.reset(seed, { speed_cap: 40, frame_skip: 1, max_steps: 90000 });
let mem = pol.init(), done = false, steps = 0, lastHp = obs.player.hp;
let chosenHitButFreeExisted = 0, totalChosenHits = 0, newBulletHits = 0;
while (!done && steps < 90000) {
  const boss = obs.objects.some(o => o.type === "boss");
  const out = pol.policy(obs, mem); mem = out.mem;
  const chosen = out.action.move;
  let info = null;
  if (boss && chosen) {
    const chosenIsHit = t1hit(obs, chosen);
    const freeCount = anyHitFreeInMySet(obs);
    if (chosenIsHit) { totalChosenHits++; if (freeCount > 0) { chosenHitButFreeExisted++; info = { freeCount }; } }
  }
  const r = env.step(out.action);
  const eff = r.obs.player.hp + (r.obs.player.shield_hp || 0);
  if (boss && eff < lastHp && info) {
    // a damage happened and our chosen move was a predicted hit while a free move existed
  }
  lastHp = eff; obs = r.obs; done = r.done; steps++;
}
console.log(`seed ${seed} ${obs.reward_info.done_reason} | chosen-move-was-a-t1-hit: ${totalChosenHits} times; of those, a hit-free move existed in MY set: ${chosenHitButFreeExisted}`);

