"use strict";
const { RogueEnv } = require("./env.bundle.js");
const pol = require("./policy.js");
const seed = Number(process.argv[2] || 7);
const env = new RogueEnv();
let { obs } = env.reset(seed, { speed_cap: 40, frame_skip: 1, max_steps: 90000 });
let mem = pol.init(), done = false, steps = 0, lastEff = obs.player.hp + (obs.player.shield_hp || 0);
let prev = obs;
while (!done && steps < 90000) {
  const out = pol.policy(obs, mem); mem = out.mem;
  const r = env.step(out.action); steps++;
  const eff = r.obs.player.hp + (r.obs.player.shield_hp || 0);
  if (eff < lastEff) {
    const drop = lastEff - eff;
    // examine PREV obs (what the policy saw) and the chosen move
    const [px, py] = prev.player.pos;
    const [npx, npy] = r.obs.player.pos; // pos after move
    // nearest bullet to NEW player pos using prev-frame bullet predicted +1
    let nbd = 1e9, nb = null, nbodyd = 1e9, nbody = null;
    for (const o of prev.objects) {
      if (o.type === "enemy_bullet") { const d = Math.hypot(o.pos[0] + o.vel[0] - npx, o.pos[1] + o.vel[1] - npy) - o.size[0] / 2; if (d < nbd) { nbd = d; nb = o; } }
      if (o.type === "enemy" || o.type === "enemy_elite" || o.type === "boss") { const d = Math.hypot(o.pos[0] + o.vel[0] - npx, o.pos[1] + o.vel[1] - npy) - o.size[0] / 2; if (d < nbodyd) { nbodyd = d; nbody = o; } }
    }
    const src = (nbd < 16) ? "BULLET" : (nbodyd < 16) ? "BODY:" + (nbody.enemy_type || nbody.variant || nbody.type) : "UNKNOWN";
    console.log(`drop ${String(drop).padStart(4)} @s${steps} ${src} | nearestBulletGap ${nbd.toFixed(1)} (dmg ${nb ? nb.dmg : "-"}) | nearestBodyGap ${nbodyd.toFixed(1)} | playerMoved [${(npx - px).toFixed(0)},${(npy - py).toFixed(0)}] inv ${r.obs.player.invincible_ms}`);
  }
  lastEff = eff; prev = r.obs; obs = r.obs; done = r.done;
}
console.log("end:", obs.reward_info.done_reason, "step", steps, "lvl", obs.player.level);

