  const c = [[0, 0]];
  // dense angular + radial coverage so a hit-free escape into a gap is always reachable
  const N = 32, mags = [SPEED, SPEED * 0.72, SPEED * 0.45, SPEED * 0.22];
  for (let a = 0; a < N; a++) {
    const ang = (a / N) * Math.PI * 2, cx = Math.cos(ang), sy = Math.sin(ang);
    for (const m of mags) c.push([cx * m, sy * m]);
