"use strict";
// Box-collision forced-hit measurement. At each boss step, does a hit-free move exist
// (box model), and did we take damage anyway?
const { RogueEnv } = require("./env.bundle.js");
const pol = require("./policy.js");
const SPEED = 40;
const CANDS = (() => { const c = [[0, 0]]; for (let a = 0; a < 48; a++) { const ang = a / 48 * Math.PI * 2; for (const m of [SPEED, SPEED * 0.7, SPEED * 0.45, SPEED * 0.22]) c.push([Math.cos(ang) * m, Math.sin(ang) * m]); } return c; })();
function hitFreeCount(obs) {
  const [px, py] = obs.player.pos, W = obs.field.w, H = obs.field.h;
  const PW = obs.player.size[0] / 2, PH = obs.player.size[1] / 2;
  const bs = obs.objects.filter(o => o.type === "enemy_bullet");
  const bodies = obs.objects.filter(o => o.type === "enemy" || o.type === "enemy_elite" || (o.type === "boss" && !o.in_cutscene));
  let free = 0;
  for (const mv of CANDS) {
    let nx = px + mv[0], ny = py + mv[1];
    if (nx < PW) nx = PW; else if (nx > W - PW) nx = W - PW;
    if (ny < PH) ny = PH; else if (ny > H - PH) ny = H - PH;
    let hit = false;
    for (let t = 1; t <= 3 && !hit; t++) {
      for (const b of bs) { const dx = Math.abs(b.pos[0] + b.vel[0] * t - nx), dy = Math.abs(b.pos[1] + b.vel[1] * t - ny); if (dx < PW + b.size[0] / 2 && dy < PH + b.size[1] / 2) { hit = true; break; } }
      for (const e of bodies) { const dx = Math.abs(e.pos[0] + e.vel[0] * t - nx), dy = Math.abs(e.pos[1] + e.vel[1] * t - ny); if (dx < PW + e.size[0] / 2 && dy < PH + e.size[1] / 2) { hit = true; break; } }
    }
    if (!hit) free++;
  }
  return free;
}
for (const seed of (process.argv[2] || "101,199,512").split(",").map(Number)) {
  const env = new RogueEnv();
  let { obs } = env.reset(seed, { speed_cap: 40, frame_skip: 1, max_steps: 90000 });
  let mem = pol.init(), done = false, steps = 0, lastHp = obs.player.hp + (obs.player.shield_hp || 0);
  let bossSteps = 0, forced = 0, hits = 0, hitsForced = 0;
  while (!done && steps < 90000) {
    const boss = obs.objects.some(o => o.type === "boss");
    const fc = boss ? hitFreeCount(obs) : 1;
    const out = pol.policy(obs, mem); mem = out.mem;
    const r = env.step(out.action); steps++;
    const eff = r.obs.player.hp + (r.obs.player.shield_hp || 0);
    if (boss) { bossSteps++; if (fc === 0) forced++; if (eff < lastHp) { hits++; if (fc === 0) hitsForced++; } }
    lastHp = eff; obs = r.obs; done = r.done;
  }
  console.log(`seed ${seed} ${(obs.reward_info.done_reason||"").padEnd(7)} lvl ${obs.reward_info.level} | bossSteps ${bossSteps} forcedSteps ${forced} (${(100*forced/Math.max(1,bossSteps)).toFixed(2)}%) | hits ${hits}, forced ${hitsForced}, avoidable ${hits - hitsForced}`);
}

