"use strict";
const pol = require("./policy.js");

function valid(out) {
  if (!out || !out.action) return false;
  const a = out.action;
  if (!Array.isArray(a.move) || a.move.length !== 2) return false;
  if (typeof a.move[0] !== "number" || typeof a.move[1] !== "number") return false;
  if (!isFinite(a.move[0]) || !isFinite(a.move[1])) return false;
  return true;
}

