"use strict";
// Parallel multi-seed evaluator (uses all cores). Usage: node eval_par.js [seedlist]
const { fork } = require("child_process");
const os = require("os");

const SEEDS = (process.argv[2] ||
  "1,11,23,42,57,88,101,137,199,256,314,451,512,2,3,7,99,123,5,13,17,33,71,200,8,19,44,60,77,91,150,222,303,404,505,606,707,808,909,42424")
  .split(",").map(Number);
const maxSteps = Number(process.argv[3] || 90000);

if (process.env.WORKER_SEED) {
  // worker: run one seed, print JSON
  const { RogueEnv } = require("./env.bundle.js");
  delete require.cache[require.resolve("./policy.js")];
  const pol = require("./policy.js");
  const seed = Number(process.env.WORKER_SEED);
  const env = new RogueEnv();
  let { obs } = env.reset(seed, { speed_cap: 40, frame_skip: 1, max_steps: maxSteps });
  let mem = pol.init ? pol.init() : {}, done = false, steps = 0, winStep = null, err = null;
  while (!done && steps < maxSteps) {
    let out; try { out = pol.policy(obs, mem); } catch (e) { err = String(e.message || e); break; }
    mem = out.mem; const r = env.step(out.action); obs = r.obs; done = r.done; steps++;
    if (r.event && r.event.kind === "game_over" && r.event.reason === "win") winStep = steps;
  }
  const ri = obs.reward_info;
  process.send({ seed, reason: ri.done_reason, winStep, steps, lvl: ri.level, kills: ri.kills, prog: +(ri.progress || 0).toFixed(3), bhd: +((ri.boss_hp_destroyed) || 0).toFixed(3), err });
  process.exit(0);
}

// master
const N = Math.max(1, Math.min(SEEDS.length, (os.cpus().length || 4) - 1));
const queue = SEEDS.slice();
const results = [];
let active = 0;
function launch() {
  while (active < N && queue.length) {
    const seed = queue.shift();
    active++;
    const child = fork(__filename, [SEEDS.join(","), String(maxSteps)], { env: Object.assign({}, process.env, { WORKER_SEED: String(seed) }) });
    child.on("message", (m) => results.push(m));
    child.on("exit", () => { active--; if (queue.length) launch(); else if (active === 0) finish(); });
  }
}
function finish() {
  results.sort((a, b) => SEEDS.indexOf(a.seed) - SEEDS.indexOf(b.seed));
  let wins = 0, total = 0;
  const winSteps = [];
  for (const r of results) {
    const won = r.reason === "win";
    if (won) { wins++; winSteps.push(r.winStep); }
    const escore = won ? 1 + (90000 - r.winStep) / 90000 : (r.prog || 0);
    total += escore;
    console.log(`seed ${String(r.seed).padStart(5)} | ${r.err ? "ERR " + r.err : (r.reason || "").padEnd(7)} | escore ${String(escore.toFixed(3)).padStart(6)} | win@${r.winStep || "-"} lvl ${String(r.lvl).padStart(2)} kills ${String(r.kills).padStart(4)} prog ${r.prog} bhd ${r.bhd}`);
  }
  winSteps.sort((a, b) => a - b);
  const med = winSteps.length ? winSteps[Math.floor(winSteps.length / 2)] : 0;
  console.log(`\nWINS: ${wins}/${results.length}   mean eval_score: ${(total / results.length).toFixed(4)}   win-step[min/med/max]: ${winSteps[0] || "-"}/${med || "-"}/${winSteps[winSteps.length - 1] || "-"}`);
}
launch();

